/// </remarks>
public void InfoObject.UpdateImportCustomizationScript( ICmdUI cmdUI )
/// <summary>
/// Возвращает ссылку на экспортированный файл кастомизации
/// </summary>
/// <param name="obj">Объект с кодом кастомизации</param>
/// <returns>Сведения об экспортированном файле</returns>
public FileInfo InfoObject.GetCustomizationFileInfo( ScriptingBaseObject obj )
/// <summary>
