public override void UpdateState( EntityAttribute attr, ICmdUI cmdUI )
{
 InfoObject obj = (InfoObject)attr.OwnerObject;
 cmdUI.Enabled = !obj.IsDirty && obj.IsExisting && !attr.IsEmpty && Service.UI.IsMSVSIntegrationAvailable;
}
