ISearchPanel searchPanel = Service.UI.Search( searchOp, autoRun );

// Или получить текущую панель, приведя её к интерфейсу вкладки поиска:
ISearchPanel searchPanel = Service.UI.ActiveBrowserPanel as ISearchPanel; 
