}


// Интерфейс элемента UI, связанного с некоторым скриптовым объектом.
// Например окна свойств, элементы списков и деревьев и прочие
public interface IScriptingObject
{
  // Скриптовой объект, отображаемый или редактируемый данным UI компонентом
