}

Интерфейс поисковой панели (ISearchPanel)
Вкладку поиска можно открыть программно через методы статического класса Service.UI:
// Открытие вкладки поиска по поисковой операции с возможностью автозапуска преднастроенного поиска
ISearchPanel searchPanel = Service.UI.Search( searchOp, autoRun );
Или получить текущую панель, приведя её к интерфейсу вкладки поиска:
ISearchPanel searchPanel = Service.UI.ActiveBrowserPanel as ISearchPanel;
Интерфейс ISearchPanel:
// Интерфейс поисковой панели (закладки) PLM клиента
interface ISearchPanel: IBrowserPanelWithSelection
{
  // Выполнение поиска
  void Search();
  // Возвращает true если поиск выполняется в данный момент
  bool IsRunning { get; }
  // Текущая выполненная или выполняемая поисковая операция
  SearchOperation RunningSearchOperation { get; }
  // Возвращает true если поиск выполняется с учётом регистра
  bool IsCaseSensitive { get; set; }
  // Режим поиска, простой по имени, либо расширенный по поисковому дереву
  bool AdvancedFilterMode { get; set; }
  // Искомый текст для простого режима поиска
  // </summary>
  string FilterText { get; set; }
  // Прочие параметры поиска: диапазон контейнеров, шаблон искомого объекта и прочее
  FilterCriterion Range { get; }
  // Устанавливает текущий поиск по указанной поисковой операции
  void SetSearchOperation( SearchOperation searchOp );
  // Возвращает копию текущего поискового дерева
  SearchOperation GetSearchOperation();
}


// Интерфейс для панелей, у которых в том или ином виде существует понятие "выбранный объект".
// В текущей версии это панели поиска
public interface IBrowserPanelWithSelection: IBrowserPanel
{
  // Выбранный в панели объект
  ScriptingObject SelectedObject { get; set; }
  // Число выделенных в данный момент объектов
  int SelectedCount { get; }
  // Выбранные в панели объекты
