Обработчики кастомизации

Обзор скриптовой кастомизации клиента
Обработчики кастомизации для автоматизации клиентского приложения решают несколько специфичных задач:
действия при запуске клиента (OnStarted);
программная кастомизация содержимого служебных панелей в окне клиентского приложения;
поддержка контекстной справки;
возможность переопределения функциональности хранения конфигураций на сервере дистрибутивов (обновление, отправка, блокировка);
диагностика операций загрузки объектов в клиентский кэш и поисковых серверных запросов;
расширение логики операций с сервером управления разработкой конфигураций: запрос параметров подключения к серверу управления и выполнение операции с сервером управления разработкой;
переопределение вызова просмотровщика файлов (InvokeFileViewer), например для отображения видео и аудио без предварительного скачивания файла во временную папку.
Устройство скрипта кастомизации на уровне БИС

Вызов просмотровщика файлов (InvokeFileViewer)
Вызывается внутри штатного кода открытия файла через гиперссылку в редакторе файлового атрибута, а так же через ссылку на присоединённый файл в чатах.
bool InvokeFileViewer( obj, fileAttr )
В обработчик передаётся объект, которому принадлежит файловый атрибут и сам атрибут. Скриптовой код может самостоятельно показать пользователю файл и вернуть true. В этом случае другие обработчики и штатный код ничего больше не делает. Либо обработчик возвращает false, тогда после вызова прочих имеющихся обработчиков сработает штатный код, который скачает файл во временную папку и попытается его открыть средствами операционной системы.
Собственный просмотровщик файла может быть полезен например для просмотра видео и аудио файлов с использованием потокового скачивания файла с ФС, минуя фазу предварительного сохранения файла во временную папку. Например может использоваться такой код:
public override bool InvokeFileViewer( ScriptingObject obj, Attribute fileAttr )
{
  // Если нажат Ctrl или Shift, ничего не делаем, передаём открытие файла операционной системе
  if( Win32.Keyboard.IsKeyDown( Keys.ShiftKey ) || Win32.Keyboard.IsKeyDown( Keys.ControlKey ))
    return false;
  var f = fileAttr.Value.GetValue<FileDesc>();
  if( f == null || !f.IsExisting || !f.IsFileBodyExists )
    return false;


  // Проверяем расширение имени файла. Если это видео или аудио, то показываем пользователю виртуальный диалог для просмотра файла
  var ext = Path.GetExtension( f.OriginalName ).ToLower();
  var validExtensions = new[] {".mp4",".mp3",".mp2",".mkv",".avi",".mpeg",".webm",".ogg",".aac",".wav"};
  if( validExtensions.Contains( ext ) )
  {
    var viewer = new InfoObject( Service.GetTemplate( @"InfoObjects\BIS\Dialogs\VideoViewer" ) );
    viewer.IsNonPersisted = true;
    viewer.PropertyBag["FileAttr"] = fileAttr;
    Service.UI.ShowObjectPropertiesModeless( viewer, true );
    return true;
  }

  return false;
}
В вызываемом виртуальном диалоге может использоваться HTML атрибут, содержимое которого формируется примерно таким кодом вычисления атрибута:
  // Из obj.PropertyBag виртуального диалога достаём файловый атрибут, 
  // который собираемся показать пользователю
  var fileAttr = obj.PropertyBag.Get<Attribute>("FileAttr");
  var file = fileAttr.Value.GetValue<FileDesc>();
  var owner = fileAttr.OwnerObject;


  // Формируем путь к файловому атрибуту. Если это атрибут верхнего уровня, то нужен просто его ключ.
  // Если же это атрибут элемента списка, то формируем путь в таком виде: FileList.ID-элемента.File
  var fileAttrKey = fileAttr is SubItemAttribute 
        ? ((SubItemAttribute)fileAttr).Owner.OwnerElements.Reverse().
            Select( o => $"{o.Owner.NameKey}.{o.Id}" ).
            ConcatValues( fileAttr.NameKey ).
            JoinStrings(".", false )
        : fileAttr.NameKey;

  var videoLink = "";
  if( file != null && file.IsFileBodyExists && file.IsExisting )
     videoLink = Service.UI.FormatHttpLink( owner.Entity, owner.Id, fileAttrKey );    
  var videoPart = 
      @"<div style=""height:100vh;"">" +
      @"<VIDEO style=""background-color: grey;height:100vh;"" src=""" + HtmlTools.HtmlEncode( videoLink ) + @""" width=""100%"" preload=""metadata"" autoplay=""true"" controls=""true""></VIDEO>" +
       "</div>";    
  return videoPart;

Диагностика запросов на загрузку объектов (OnLoadRequest)
Вызывается в клиентском приложении при запросах на загрузку объектов. Может использоваться для диагностики стеков, в которых происходят запросы на загрузку объектов.
void OnLoadRequest( string operationName, EntityIdentifier entity, ulong[] ids, Guid[] guids, LoadRequestOptions options )

// Набор опций для различных вариантов загрузки объектов
public struct LoadRequestOptions
{
   // Флаги предварительной загрузки ИО
   PreloadModeEnum? preloadMode;

   // Флаги загрузки дерева контейнеров
   CmdLoadContainersBase.CmdFlags? containerFlags;

   // Флаги загрузки задач WF
   TaskLoadStateFlags? taskLoadMode;

   // Признак неблокирующей предварительной загрузки
