}

Диагностика запросов серверного поиска (OnSearchRequest)
Вызывается в клиентском приложении при запросах на серверный поиск чего-либо. Может использоваться для диагностики стеков, в которых происходят поисковые запросы.
void OnSearchRequest( SearchOperationBase operation, bool asynchronous )
Внутри метода можно добавить запись в лог или создать серверный репорт со стеком, чтобы отследить какой именно код привёл к выполнению поискового запроса:
public override void OnSearchRequest( SearchOperationBase operation, bool asynchronous )
{
    Service.WriteToServerLog( "OnSearchRequest {0} session='{1}' asynchronous={2}", operation.ToString(), operation.UserSesion, asynchronous );

    // Для поисковых запросов из скриптового кода снимаем стек (репорт попадёт в папку Reports\Internal на сервере)
    if( operation.Name != "Клиентский поиск" )
      Service.ReportError( "Поисковый запрос из скриптового клиентского кода: {0}", operation );
}
Для программной идентификации поисковых запросов может использоваться имя запроса operation.Name, которое может устанавливаться скриптом, выполняющим поисковую операцию:
var op = new SearchOperation( EntityIdentifier.InfoObject, "Имя поисковой операции" );
Клиентский поиск из панели поиска так и называется "Клиентский поиск".
Примечание: Исключения внутри этого метода остаются в серверных репортах и не влияют на прочую работу сервера.

Обновление конфигурации с сервера дистрибутивов (DoDownloadConfiguration)
Вызывается в клиенте по кнопке "Скачать обновление" в форме свойств конфигурации. Штатное действие этой кнопки - скачивание конфигурации с сервера дистрибутивов и импорт его в текущую систему. Кастомизатор позволяет переопределить способ хранения конфигураций на внешнем сервере.
bool DoDownloadConfiguration( Configuration cfg )
Если обработчик вернул true, то считается, что он сделал всё, что следует, и другие обработчики и штатный код не вызывается.
Примечание: для безопасности передачи паролей сервер дистрибутивов следует использовать только при защищённом подключении к нему, например, через https.
Штатный код выполняет следующие действия:
Разбирает строку с адресом хранения на сервере дистрибутивов:
string server;
int serverGuidHash;
EntityIdentifier entity;
ulong id;
Service.UI.ParseWebLink( cfg.DistributiveURL, out server, out serverGuidHash, out entity, out id );
Запрашивает у пользователя логин-пароль к серверу дистрибутивов.
Формирует http(s) запрос для получения конфигурации с сервера хранения:
   try
   {
    ServicePointManager.ServerCertificateValidationCallback += ValidateRemoteCertificate;

    using( new WaitCursor() )
    using( var client = new WebClient() )
    {
     var response = client.UploadValues( string.Format( "https://{0}/api/configuration/get", server ), new NameValueCollection
     {
      { "version", cfg.Version },
      { "folder", id.ToString() },
      { "userLogin", info.Username },
      { "userPassword", info.Password },
      { "serverGuid", Service.DatabaseInstanceGUID.ToString() },
      { "serverName", GetFriendlyServerName() },
      { "locale", Service.CurrentLanguage }
     } );
     var result = System.Text.Encoding.UTF8.GetString( response );
     if( !result.StartsWith( "<?xml", StringComparison.InvariantCultureIgnoreCase ) )
     {
      var converter = new HtmlToText();
      throw new HumanFaultException( converter.Convert( result ) );
     }
     var doc = new XmlDocument();
     doc.LoadXml( result );
     var root = doc.DocumentElement;
     var type = root.GetAttribute( "type" );
     var errorCode = root.GetAttribute( "errorCode" );
     var message = root.InnerText;
     var icon = MessageBoxIcon.Information;
     if( errorCode != "UserNotFound" )
      SaveLoginInfo( server, info );
     switch( type.ToLower() )
     {
      case "success":
       cfg.ImportPack( Convert.FromBase64String( message ) );
       return;
      case "info":
       break;
      case "error":
       icon = MessageBoxIcon.Warning;
       break;
     }
     UIService.ShowMessage( message, MessageBoxButtons.OK, icon );
    }
   }
   catch( Exception ex )
   {
    Service.HandleException( ex, UIStrings.ScriptingObjectExtensions_DistributiveUpdateError );
   }
   finally
   {
    ServicePointManager.ServerCertificateValidationCallback -= ValidateRemoteCertificate;
   }
При этом метод ValidateRemoteCertificate в зависимости от настройки реестра разрешает или не разрешает использовать самовыпущенные сертификаты при https соединениях:
  private static bool ValidateRemoteCertificate( object sender, X509Certificate cert, X509Chain chain, SslPolicyErrors error )
  {
   if( error == SslPolicyErrors.RemoteCertificateNotAvailable )
    return false;

   // If the certificate is a valid, signed certificate, return true.
   if( error == SslPolicyErrors.None )
    return true;

   // Разрешаем ошибки сертификатов
   return Service.GetCommonRegistryValue( @"SystemSettings\ConfigurationUpdate\RequireStrongCertificate\Value", 1 ) == 0;
  }
Выполняет импорт конфигурации:
  static void ImportPack( this Configuration cfg, byte[] data )
  {
   ConfigurationPackReader reader;
   try
   {
    using( new WaitCursor() )
    using( var stream = new MemoryStream( data ) )
    {
     reader = new ConfigurationPackReader( stream );
     reader.PackFilePath = cfg.DistributiveURL;
    }
   }
   catch( Exception e )
   {
    UIService.HandleException( e, String.Format( Messages.ConfigurationUITools_ImportConfigurationPack_ReadFailure, cfg.DistributiveURL ) );
    return;
   }
   using( var form = new FormImportConfigurationPacket( reader, cfg.DistributiveURL ) )
     form.ShowDialog();
  }

