Пример кнопки экспорта одиночной UI команды
Кнопка на верхней панели инструментов для выполнения каких-либо действий, полезных конфигуратору системы. Например, экспорт одиночной UI команды. В штатном интерфейсе команды экспортируются вместе со своим шаблоном или конфигурацией. Если необходимо перенести через пакет конфигурации одиночную команду UI, это можно сделать скриптовым действием типа "Клиентская задача с ручным запуском" со следующим кодом:
// Получение объекта, выделенного в данный момент в активной панели клиентского приложения
ScriptingObject GetSelectedObject()
{
    var panel = Service.UI.ActiveBrowserPanel != null ? Service.UI.ActiveBrowserPanel.TargetPanel : null;
    var lv = panel as ListView;
    var tv = panel as TreeView;
    var prop = panel as IPropertySheetCallback;
    if( lv != null )
    {
        if( lv.VirtualMode )
        { // Для списков в виртуальном режиме выделенные элементы достаём через индексы
            var index = lv.SelectedIndices.Count > 0 ? lv.SelectedIndices[0] : -1;
            var item = index >= 0 ? lv.Items[index] : null;
            if( item is IUIItem )
                return ((IUIItem)item).GetObject();
        }
        else
        { // Для списков в обычном режиме режиме выделенные элементы достаём напрямую
            var item = lv.SelectedItems.Count > 0 ? lv.SelectedItems[0] : null;
            if( item is IUIItem )
                return ((IUIItem)item).GetObject();
        }
    }
    else if( tv != null )
    { // Выделенный узел в дереве
        var item = tv.SelectedNode;
        if( item is IUIItem )
            return ((IUIItem)item).GetObject();
    }
    else if( prop != null )
    { // Объект во вкладке свойств
        return prop.ScriptingObject;
    }

    return null;
}

// Делаем команду доступной, только если выделена UI команда
public override void UpdateState( ICmdUI cmdUI )
{
    cmdUI.Enabled = GetSelectedObject() is UICommand;
}

// Собственно действие кнопки. Из выделенного объекта формируем пакет конфигурации
public override Object Invoke( UserSession session, Object inputParams )
{
      var obj = GetSelectedObject();
      if( obj is UICommand )
      {
            var exporter = new ProgramSoyuz.PLM.Scripting.ImportExport.PlainObjectExporter<UICommand>();
            exporter.Add( (UICommand)obj );
            exporter.SaveWithUI( Helpers.PrepareFileName( obj.SafeToString() ), ConfigurationImportFlags.All );
      }
      return null;
}

Пример скриптового действия, которое открывает эту справку в отдельной вкладке
Клиентское скриптовое действие с ручным запуском. Команда добавлена в меню Справка. Следующий код кастомизации делает команду видимой, если объекты справки установлены. Обработчик действия проверяет, есть ли уже панель со справкой, если да, активирует ее. Если нет, открывает новую панель.
/// <summary>
/// Обновление состояния элементов интерфейса
/// </summary>
/// <param name="cmdUI">Объект для управления контролом вызова команды</param>
public override void UpdateState( ICmdUI cmdUI )
{
    var target = GetHelpRoot();
    cmdUI.Visible = target != null;
}

/// <summary>
/// Вызов метода, реализованного скриптовой функцией
/// </summary>
/// <param name="session">Пользовательская сессия, инициировавшая вызов 
/// (может быть null, если вызов инициировал серверный скрипт без указания сессии)</param>
/// <param name="inputParams">Сериализуемые входные данные для метода</param>
/// <returns>Результат работы метода</returns>
public override Object Invoke( UserSession session, Object inputParams )
{
    var target = GetHelpRoot();

    // Получаем локализованное имя этого скриптового действия
    var name = ((ScriptingTask)Owner).NameUILocalized;

    // Ищем уже открытую панель справки по имени
    var existingTab = Service.UI.GetBrowserPanelsFromAllGroups().
        FirstOrDefault( o => o.Name == name );
    if( existingTab != null )
    {
        existingTab.Activate();
        return null;
    }

    // Открываем панель и устанавливаем ей активную вкладку
    var panel = Service.UI.OpenInNewTabPage( target, false ) as IBrowserPanelWithProperties;
    if( panel != null )
    {
      panel.PropertiesPanel.ButtonStripVisibility = false;
      panel.PropertiesPanel.SelectedCustomPageName = "TableOfContents";
      #if BISv3
      panel.Name = name;
      #endif
    }

    return null;
}
AttributableObject GetHelpRoot()
{
    var docsRoot = Service.GetDataContainer( @"Documentation" );
    if( docsRoot == null )
        return null;

    var culture = CultureInfo.CurrentCulture.TwoLetterISOLanguageName;
    var helpRoot = docsRoot.GetChild( culture );

    if( helpRoot == null && culture != "en" )
        helpRoot = Service.GetDataContainer( @"Documentation\en" ); 
    if( helpRoot == null && culture != "ru" )
        helpRoot = Service.GetDataContainer( @"Documentation\ru" ); 
    if( helpRoot == null )
        return null;
    var onlineHelp = helpRoot.GetChild("OnlineHelp");
    if( onlineHelp == null )
        return null;

    return onlineHelp;
}

Выполнение скриптового действия (Invoke)
Вызывается по скриптовому запросу с клиента или сервера там, где вызвали.
void Invoke( UserSession session, Object inputParams )
Скриптовой обработчик реализует собственно скриптовое действие.
В параметре session передаётся текущая пользовательская сессия, если вызов произошёл в контексте пользователя.
В параметр inputParams передаётся параметр вызова.
var task = Service.GetScriptinTask( "ключ-действия" );
var inputParams = new NamedArgs();
inputParams["Arg1"] = 123;
task.Invoke( inputParams );
task.InvokeOnServer( inputParams, async );
На сервере скриптовое действие можно вызвать асинхронно с использованием функции обратного вызова или события о завершении:
Для вызова скриптового действия так же имеются соответствующие сигнатуры:
var op = new AsyncInvokeOperation( o => 
       {
         // По готовности результата сработает этот код
         if( o.ResultException != null )
             Service.HandleException(o.ResultException, false);
         else
             Service.UI.ShowMessage( "Результат = " + o.Result.SafeToString());
       }
    );


// Получаем скриптовое действие
var scriptingTask = Service.GetScriptingTask("ключ-действия");

var inputParams = new NamedArgs();
inputParams["Arg1"] = 123;


// Вызываем его на сервере
op.InvokeOnServer( scriptingTask, inputParams );

Время последнего запуска
Отображает время последнего запуска фонового скриптового действия.
Скриптовой доступ:
// Локальное дата/время последнего запуска скриптового действия
DateTime ScriptingTask.LastRunDate;

Запускать по
Настройка времени запуска фонового автоматического действия.
Задача важнее текущих серверных операций - установлен бит RealTimeTask.
В этом случае при наступлении времени запуска сервер не обращает внимания на свою занятость. Если флаг не установлен, то сервер может отложить запуск, когда не будет текущих высоко приоритетных задач.
Сразу после сохранения задачи - установлен бит RunOnSave.
В этом случае задача поступает в очередь на запуск сразу после сохранения.
Если установлен Тип повтора запуска "раз в сутки в указанные дни недели", то для каждого дня недели устанавливается флаг пропуска запуска действия в этот день.
Скриптовой доступ:
ScriptingTaskBase.ScheduleFlagsEnum ScriptingTask.ScheduleFlags;

enum ScheduleFlagsEnum: uint
{
   Default = 0x0000,
   // Запустить фоновую задачу сразу после сохранения
   RunOnSave = 0x0001,

   // Не запускать по понедельникам
   SkipMonday = 1 << 1,
   // Не запускать по вторникам
   SkipTuesday = 1 << 2,
   // Не запускать по средам
   SkipWednesday = 1 << 3,
   // Не запускать по четвергам
   SkipThursday = 1 << 4,
   // Не запускать по пятницам
   SkipFriday = 1 << 5,
   // Не запускать по субботам
   SkipSaturday = 1 << 6,
   // Не запускать по воскресениям
   SkipSunday = 1 << 7,

   SkipFlags = SkipMonday | SkipTuesday | SkipWednesday | SkipThursday | SkipFriday | SkipSaturday | SkipSunday,

   // Задача при запуске попадает в очередь приоритетных для запуска задач
   RealTimeTask = 1 << 8,
}

Сведения о последнем запуске
Отображает сведения о последнем запуске фонового скриптового действия.
Скриптовой доступ:
