Пример отправки PUSH сообщения через запрос к внешнему серверу
Имеются два подключённых друг к другу сервера. На одном из них настроен веб-доступ, мобильное приложение и подключён сервис PUSH сообщений. На втором сервере требуется тоже по некоторым событиям отправлять PUSH сообщения.
Для этого на первом сервере, на котором настрое веб доступ реализуем обработчик запросов к внешнему серверу (к нему):
/// <summary>
/// Вызов метода, реализованного внешним сервером
/// </summary>
/// <param name="server">Сервер, от которого пришёл запрос</param>
/// <param name="method">Имя запрос</param>
/// <param name="data">Данные запроса</param>
/// <returns>Результат обработки</returns>
public override Object Invoke( ExternalServer server, String method, Object data )
{
    // Если запрос от незнакомого сервера, ничего не делаем
    if( server.NameKey != "OFFICE" )
        return null;

    switch( method )
    {
        case "PushMessageToUser":
        {
            var args = data as NamedArgs;
            var login = args?.GetString("UserLogin");
            var name = args?.GetString("UserName");

            // Находим локальных пользователей с таким же логином и именем
            var users = Service.GetAllUsers( true, false, true ).Where( o => o.AccountId == login && o.ToString() == name ).ToArray();


            // Отправляем им PUSH сообщения
            users.ForEach( o => DoPushMessageToUser( o, args ) );
            return true;
        }
    }

    return null;
}




Object DoPushMessageToUser( User user, NamedArgs args )
{
    // В контексте пользователя вызываем Invoke метод учётки, выполняющий отправку PUSH сообщения тем пользователем, 
    // которые заходили на сервер через мобильное приложение.
    using( Service.ScriptExecutionContext.Enter( user, null, false ) )
    {
        user.Invoke( "SendPushNotification", args );
    }

    return null;
}
На втором сервере в данном случае в модификаторе шаблона чата реализуем логику уведомления пользователей через PUSH сообщения о новых входящих сообщениях в этом чате:
public override void OnAfterCommit( InfoObject obj )
{
  var messagePreview = Service.SaveSetPropertyBag.GetValueIfAny("NewMessageInChat" + obj.Id).GetValueOfType<String>();
  if( messagePreview.IsEmpty() )
    return;

  // Сформируем текст сообщения и список адресатов для получения PUSH сообщения
  var thisUser = Service.GetCurrentUser() ?? User.System;
  var users = obj.GetCollectionElements( "Participants" ).
     Where( ce => !ce.GetBoolean("NoPushNotifications") ).
        Select( ce => ce.GetUser( "User" ) ).
        SkipNull().
        Where( o => o != thisUser ).Distinct().
        ToArray();
  if( !users.IsEmpty() )
  {
     if( obj.GetCollectionElements("Participants").Count() > 2 )
         messagePreview = thisUser.ToString() + ": ";
     else
         messagePreview = "";

     messagePreview += "сообщение в чате на сервере " + Service.PublicServerName + "."; 

     var args = new NamedArgs();
     args["text"] = messagePreview;
     args["ttl"] = TimeSpan.FromDays(7);
     args["title"] = obj.ToString();

     var lastMessageNum = obj.GetInteger("LastMessageNumber");

     // В потоке системного пула выполним вызов внешнего сервера
     Service.MT.RunLater( d => LazySendPushNotifications( obj, lastMessageNum, users, args ), null, TimeSpan.FromSeconds(120) );
  }
}

void LazySendPushNotifications( InfoObject obj, int originalMessageNum, User[] users, NamedArgs args )
{
  // Проверяем, что нужный нам сервер доступен
  var s = Service.GetExternalServer("PUBLIC");
  if( s == null || !s.IsOperational )
     return;
  try
  {
    if( !obj.IsWrappedObjectAlive )
      return;

    var lastMessageNum = obj.GetInteger("LastMessageNumber");
    var itemsByUser = obj.GetCollectionElements( "Participants" ).ToDictionary( o => o.GetUser("User") );

    foreach( var user in users )
    {
      var el = itemsByUser.GetValueIfAny( user );
      if( el == null )
        continue;

      // Если пользователь уже был в чате после исходного сообщения, то ничего не делаем
      var lastUserViewedNum = el.GetInteger("LastViewedMessageNumber");
      var lastUserPostedNum = el.GetInteger("LastSentMessageNumber");
      if( lastUserViewedNum >= originalMessageNum || lastUserPostedNum >= originalMessageNum )
        continue;

      using( Service.ScriptExecutionContext.Enter( user, null, false ) )
      {
         // Название чата для каждого пользователя может быть своё
         args["title"] = obj.ToString();
      }

      if( !s.IsOperational )
         break;

      try
      {
          // Передадим на внешний сервер логин и имя пользователя, чтобы код внешнего сервера мог бы найти 
          // соответствующего локального пользователя
          args["UserLogin"] = user.AccountId;
          args["UserName"] = user.ToString();

          // Вызов внешнего сервера без ожидания ответа
          s.InvokeOneWay( "PushMessageToUser", args );
      }
      catch( Exception e )
      {
          Service.HandleException( e );
      }
    }
  }
  catch( Exception e )
  {
    Service.ReportException(e, "Рассылка PUSH уведомлений для чата ", obj.GetFormalName() );
  }
  finally
  {
    // Метод работает в потоке системного пула, потому обязательное освобождение серверных ресурсов
    Service.MT.CleanupAfterPoolThreadExecution();
  }
}

Обработчик запросов к клиентской сессии
Скриптовое действие данного типа позволяет задать метод, который можно вызывать из скриптов, работающих на сервере или других клиентских приложениях. Определены следующий обработчики:
Invoke - собственно вызов действия,
OnBeforeInvoke - серверная проверка запроса до обращения к сессии,
OnAfterInvoke - серверная проверка результата запроса до передачи его запросившему коду.
При помощи данного скриптового действия можно задать код, выполняющий те или иные запросы, приходящие от других клиентских сессий, или от сервера. Скриптовые возможности позволяют из скрипта, работающего на некотором клиентском месте или на сервере, отправить запрос на выбранную клиентскую сессию. Клиентская сессия выполняет запрос и вызвавшему коду приходит ответ.
Этот механизм может использоваться для:
организации каких-либо распределённые вычислений или автоматизированной обработки. Например, можно всем двум сотням подключенных клиентских сессий сказать сделать что-нибудь полезное в автоматическом режиме.
моментального взаимодействия с пользователями, если для какого-либо действия требуется моментальное подтверждение другого сотрудника.
/// <summary>
/// Вызов метода, реализованного пользовательской сессией
/// </summary>
/// <param name="callingUser">Пользователь, запросивший данную сессию</param>
/// <param name="callingSession">Пользовательская сессия, запросившая друную пользовательскую сессию</param>
/// <param name="method">Имя запрос</param>
/// <param name="data">Данные запроса</param>
/// <returns>Результат выполнения запроса</returns>
public override Object Invoke( User callingUser, UserSession callingSession, String method, Object data )
{
    return Service.GetCurrentUserSession() + " Метод: " + method + " Data: " + data + " CallingSession: " + callingSession + " User: " + callingUser;
}
/// <summary>
/// Предварительный обработчик перед отправкой запроса пользовательской сессии. Вызывается на локальном сервере
/// </summary>
/// <param name="callingSession">Пользовательская сессия, запросившая друную пользовательскую сессию</param>
/// <param name="targetSession">Целевая сессия, которой отправляется запрос</param>
/// <param name="method">Имя запрос</param>
/// <param name="data">Данные запроса</param>
/// <returns>true если обработка завершена и дальнейший поиск обработчиков не требуется</returns>
public override bool OnBeforeInvoke( UserSession callingSession, UserSession targetSession, string method, object data )
{
    return false;
}
/// <summary>
/// Обработчик результата перед отправкой ответа пользовательской сессии. Вызывается на локальном сервере
/// </summary>
/// <param name="callingSession">Пользовательская сессия, запросившая друную пользовательскую сессию</param>
/// <param name="targetSession">Целевая сессия, которой отправляется запрос</param>
/// <param name="method">Имя запрос</param>
/// <param name="data">Данные запроса</param>
/// <param name="result">Результат обработки</param>
/// <returns>true если обработка завершена и дальнейший поиск обработчиков не требуется</returns>
public override bool OnAfterInvoke( UserSession callingSession, UserSession targetSession, string method, object data, ref object result )
{
    return false;
}
Примечание. Вызывающая сессия может быть не доступна по правам доступа на исполняющем запрос клиенте.
Запрос к клиентской сессии из скриптового кода
Скриптовой код может вызывать Invoke методы пользовательской сессии. При этом в синхронном режиме текущий поток клиента блокируется. В асинхронном режиме по готовности будет либо установлено событие синхронизации, либо вызван установленный обработчик обратного вызова.
var thisSession = Service.GetCurrentUserSession();
var session = Service.GetUserSessions().FirstOrDefault( o => o != thisSession );
// Синхронный вызов
var res = session.Invoke( "TestMethod", "TestData" );

// Синхронный вызов без ожидания ответа
res = session.InvokeOneWay( "TestMethod", "TestData" );

// Асинхронный вызов
var op = new AsyncInvokeOperation( "TestMethod", "TestData", o => 
       {
         // По готовности результата сработает этот код
         if( o.ResultException != null )
             Service.HandleException(o.ResultException, false);
         else
             Service.UI.ShowMessage( "Результат = " + o.Result.SafeToString());
       }
    );

op.InvokeOn(session);
...    
Примечание. При попытке асинхронного вызова Invoke-метода текущей сессии метод будет вызван в синхронном режиме.

