Пример запроса к клиентской сессии модуля интеграции с VisualStudio
Код кнопки, которая запускает автосборку проекта. При получении подтверждения от пользователя, происходит поиск сессии модуля интеграции с VisualStudio. Если сессия найдена, то формируем список объектов и выполняем односторонний вызов без ожидания ответа.
public override void Invoke( InfoObject obj )
{
    var dialogResult = Service.UI.ShowMessage( "Добавить проект в очередь на сборку?",
        MessageBoxButtons.YesNoCancel, MessageBoxIcon.Question );
    if( dialogResult != DialogResult.Yes )
        return;

    // Среди подключённых клиентских сессий ищем нужную сессию по имени
    var vsSession = Service.GetUserSessions().FirstOrDefault( s => s.SessionName.Safe().Equals( "VisualStudio" ) );
    if( vsSession == null )
    {
        Service.UI.ShowMessage( "Нет ни одной запущенной сессии Visual Studio.", MessageBoxButtons.OK,
            MessageBoxIcon.Information );
        return;
    }


    // Формируем список объектов для передачи в качестве параметра вызова
    var projects = obj.GetCollectionElements( "Projects" ).Safe().
        OrderBy( c => c.GetInteger( "Order" ) ).
        Select( c => c.GetInfoObject( "Pvc" ) ).ConcatValues( obj ).
        ToArray();

    // Выполняем односторонний вызов без ожидания ответа

    vsSession.InvokeOneWay( "VsAddinBuildProjects", projects );
}

Выполнение операции перетаскивание (drag'n'drop) (InsertDropData)
Обработчик реализует операцию перетаскивания для тех действий, которые поддерживает данный объект. По умолчанию для внутренних объектов реализован перенос объектов и создание ярлыка. При помощи этого обработчика кастомизации можно дополнить или переопределить эти операции, а также реализовать перетаскивание файлов на объекты системы.
Доступные операции при наведении мышки на конкретный объект определяются обработчиком CalcDropEffects.
Например так может выглядеть обработчик, который по файлам определённых расширений создаёт объекты соответствующих шаблонов:
/// <summary>
/// Собственно выполнение операции DND. Если в контексте присутствуют ObjectsByTemplate, обработанные объекты 
/// следует отметить флагом object.Handled.
/// </summary>
/// <param name="context">Контекст групповой DND операции</param>
/// <param name="destination">Целевой объект (UserItem, UserItemLink, AttributableObject)</param>
/// <param name="dropEffect">Выполняемая операция одна из (Move, Copy, Link)</param>
/// <returns>true если операцию следует продолжить с оставшимися объектами, false - пользователь затребовал завершение операции</returns>
/// <remarks>Операция происходит в контексте группового сохранения. Все изменения будут сохранены по завершению выполнения
/// всех обработчиков DND. Можно использовать явное сохранение обработанных объектов.</remarks>
public override bool InsertDropData( DragDropOperationContext context, ScriptingObject destination, DragDropEffects dropEffect )
{
    // Проверяем, что эта операция вызвана для обработки ИО
    // Существуют контексты, в которых ИО в принципе не отображаются, например 
    // диалог выбора контейнера. В таких контекстах вставка ИО смысла не имеет
    if( !context.IsAllowed( EntityIdentifier.InfoObject ) )
        return true;

    // Этот обработчик реализует только операцию копирования
    // Если попали сюда с другой операцией, то возможно ее сможет выполнить другой обработчик
    if( dropEffect != DragDropEffects.Copy )
        return true;

    // Определим целевой контейнер (если это контейнер)
    var c = destination as DataContainer;
    var io = destination as InfoObject;
    if( c == null && io == null )
        return true;

    // Проверим шаблон целевого контейнера - обработчик создаёт ИО внутри контейнеров шаблона Дистрибутив
    var folderTemplate = Service.GetTemplate( @"Containers\ESPD\Distributives" );
    var targetTemplate = Service.GetTemplate( @"InfoObjects\ESPD\DistributionPackage" );
    if( folderTemplate == null || targetTemplate == null )
        return true;

    if( c != null && folderTemplate == c.Template )
    {
        // Проверяем, есть ли в клипборде файлы
        if( context.RawData.GetDataPresent( DataFormats.FileDrop ) )
        {
            // Говорим другим возможным обработчикам, что мы операцию обработали,
            // дальнейший вызов обработчиков не требуется.
            // При реальном использовании возможно другие обработчики и могли бы 
            // обработать файлы других расширений, но для данного шаблона приёмника
            // других действий не требуется, поэтому блокируем вызов прочих обработчиков
            context.Handled = true;

            // Извлекаем имена файлов
            var files = context.RawData.GetData<string[]>( DataFormats.FileDrop ).Where( File.Exists );
            var existingByName = new Dictionary< String, InfoObject >( StringComparer.CurrentCultureIgnoreCase );
            c.RootInfoObjects.ForEach2( o => existingByName[ o.GetValue< String >( "FileName" ) ] = o );
            foreach( var f in files )
            {
                var name = Path.GetFileNameWithoutExtension( f );
                var targetIO = existingByName.GetValueIfAny( name );
                if( targetIO == null )
                    targetIO = new InfoObject( c, targetTemplate );
                targetIO.GetAttribute( "Body" ).Value.UploadFile( f );
            }
        }
    }
    return true;
}
Подробнее про поддержку операций перетаскивания см. Операции перетаскивания объектов и вставки из буфера обмена.

Определение операций перетаскивания (drag'n'drop) (CalcDropEffects)
Этот обработчик вызывается для определения доступных во время операции перетаскивания действий. По умолчанию для внутренних объектов реализован перенос объектов и создание ярлыка. При помощи этого обработчика кастомизации можно дополнить или переопределить эти операции, а также реализовать перетаскивание файлов на объекты системы.
Собственно операция вставки выполняется обработчиком InsertDropData.
Например так может выглядеть обработчик, который по файлам определённых расширений добавляет поддержку операции копирования:
Set<String> validExtensions = new[]
    {
        ".msi", ".pmszcfg", ".exe"
    }.SafeToSet();

/// <summary>
/// Формирует описатели доступных DND операций. Список описателей может формироваться, как единый на уровне контекста, так и 
/// частный - для каждого объекта в context.ObjectsByTemplate (если операция по атрибутируемым объектам)
/// </summary>
/// <param name="context">Контекст групповой DND операции</param>
/// <param name="destination">Целевой объект (UserItem, UserItemLink, AttributableObject)</param>
/// <remarks>В операцию могут быть вовлечены и объекты других шаблонов. Они доступны через <see cref="context"/>.</remarks>
public override void CalcDropEffects( DragDropOperationContext context, ScriptingObject destination )
{
    // Проверяем, что эта операция вызвана для обработки ИО
    // Существуют контексты, в которых ИО в принципе не отображаются, например 
    // диалог выбора контейнера. В таких контекстах вставка ИО смысла не имеет
    if( !context.IsAllowed( EntityIdentifier.InfoObject ) )
        return;

    // Определим целевой контейнер (если это контейнер)
    var c = destination as DataContainer;
    var io = destination as InfoObject;
    if( c == null && io == null )
        return;

    // Проверим шаблон целевого контейнера - обработчик создаёт ИО внутри контейнеров шаблона Дистрибутив
    var folderTemplate = Service.GetTemplate( @"Containers\ESPD\Distributives" );
    var targetTemplate = Service.GetTemplate( @"InfoObjects\ESPD\DistributionPackage" );
    if( folderTemplate == null || targetTemplate == null )
        return;

    if( c != null && c.Template.IsChildOf( folderTemplate ) )
    {
        // Проверяем, какие объекты переносятся (содержатся в буфере обмена)
        if( context.RawData.GetDataPresent( DataFormats.FileDrop ) )
        {
            // Извлекаем имена файлов
            var files = context.RawData.GetData<string[]>( DataFormats.FileDrop );

            // Проверяем, что есть хотя бы один подходящий файл
            var validFiles = files.
                Where( File.Exists ).
                Where( f => validExtensions.Contains( Path.GetExtension( f ).SafeToString().ToLower() ) ).Take( 2 ).ToArray();

            var validFilesCount = validFiles.SafeCount();
            if( validFilesCount > 0 )
            {
                // Формируем строку, поясняющую операцию перетаскивания (пользователь видит ее рядом с указателем мышки)
                string text = string.Empty;
                if( validFilesCount == 1 )
                    text = string.Format( "Импорт '{0}' в %1", Path.GetFileNameWithoutExtension( validFiles.FirstOrDefault() ) );
                else
                    text = "Импорт дистрибутивов в %1";

                // Этот обработчик поддерживает операцию копирования.
                // Добавляем её в список операций, которые можно произвести с данными
                context.AddOp( new DropEffectDesc( DragDropEffects.Copy, text, c ) );

                // Если дальнейшая обработка данного набора файлов не требуется, установим
                // признак окончательного выполнения операции этим обработчиком
                context.AreDropEffectsFinalized = true;
                return;
            }
        }
    }
}
Подробнее про поддержку операций перетаскивания см. Операции перетаскивания объектов и вставки из буфера обмена.

Выполнение автоматического действия (Invoke)
Вызывается на сервере в одном из фоновых потоков по пользовательскому выбору команды меню или кнопки на панели инструментов.
void Invoke( UserSession session, Object inputParams )
Скриптовой обработчик реализует собственно действие, затребованное пользователем.
В параметре session передаётся текущая пользовательская сессия, если выполнение команды запросил пользователь, а не серверный скрипт вне пользовательского контекста.
Параметр inputParams может быть не null, только если вызов инициировал скрипт, явно передав параметр.
var task = Service.GetScriptinTask( "ключ-действия" );
task.Invoke( inputParams );
task.InvokeOnServer( inputParams, async );

Выполнение скриптового действия (Invoke)
Вызывается на сервере по скриптовому запросу с клиента или сервера.
void Invoke( UserSession session, Object inputParams )
Скриптовой обработчик реализует собственно скриптовое действие.
В параметре session передаётся текущая пользовательская сессия, если вызов произошёл в контексте пользователя.
В параметр inputParams передаётся параметр вызова.
var task = Service.GetScriptinTask( "ключ-действия" );
var inputParams = new NamedArgs();
inputParams["Arg1"] = 123;
task.Invoke( inputParams );
task.InvokeOnServer( inputParams, async );

Время последнего запуска
Отображает время последнего запуска фонового скриптового действия.
Скриптовой доступ:
// Локальное дата/время последнего запуска скриптового действия
DateTime ScriptingTask.LastRunDate;

Запускать по
Настройка времени запуска фонового автоматического действия.
Задача важнее текущих серверных операций - установлен бит RealTimeTask.
В этом случае при наступлении времени запуска сервер не обращает внимания на свою занятость. Если флаг не установлен, то сервер может отложить запуск, когда не будет текущих высоко приоритетных задач.
Сразу после сохранения задачи - установлен бит RunOnSave.
В этом случае задача поступает в очередь на запуск сразу после сохранения.
Если установлен Тип повтора запуска "раз в сутки в указанные дни недели", то для каждого дня недели устанавливается флаг пропуска запуска действия в этот день.
Скриптовой доступ:
ScriptingTaskBase.ScheduleFlagsEnum ScriptingTask.ScheduleFlags;

enum ScheduleFlagsEnum: uint
{
   Default = 0x0000,
   // Запустить фоновую задачу сразу после сохранения
   RunOnSave = 0x0001,

   // Не запускать по понедельникам
   SkipMonday = 1 << 1,
   // Не запускать по вторникам
   SkipTuesday = 1 << 2,
   // Не запускать по средам
   SkipWednesday = 1 << 3,
   // Не запускать по четвергам
   SkipThursday = 1 << 4,
   // Не запускать по пятницам
   SkipFriday = 1 << 5,
   // Не запускать по субботам
   SkipSaturday = 1 << 6,
   // Не запускать по воскресениям
   SkipSunday = 1 << 7,

   SkipFlags = SkipMonday | SkipTuesday | SkipWednesday | SkipThursday | SkipFriday | SkipSaturday | SkipSunday,

   // Задача при запуске попадает в очередь приоритетных для запуска задач
   RealTimeTask = 1 << 8,
}

