Постобработка HTTP запроса (PostHandleWebRequest)
Вызывается на сервере следом за HandleWebRequest. Может использоваться для ведения журнала веб запросов и ответов на них.
void PostHandleWebRequest( HttpListenerContext context, WebUserSession session )
Например такой код сохраняет в серверный журнал записи об ответах на запросы с кодом ответа отличным от 200 (OK):
public override void PostHandleWebRequest( HttpListenerContext context, WebUserSession session )
{
  HttpListenerRequest request = context.Request;
  HttpListenerResponse response = context.Response;

  if( response.StatusCode == 200 )
    return;

  var url = context.Request.Url;
  var mes = String.Format( "WEB*: {0}://{1}; {2}; {3}; {4}; {5}; \"{6}\"\r\n", 
   url.Scheme, url.Host, url.AbsolutePath, 
   session.RemoteEndPoint, session.User.SafeToString(),
   response.StatusCode, response.StatusDescription
  );
  Service.WriteToServerLog( mes );
}
Примечание: context.Response может быть уже закрыт. Если так, то некоторые из его полей уже будут недоступны для чтения (будет возникать исключение).

Журналирование http запросов
Для журналирование входящих веб запросов можно использовать следующий скрипт в скриптовом действии подтипа Серверный HTTP обработчик:
/// <summary>
/// Обработчик веб запросов. Выполняется в серверных потоках-обработчиках сетевых запросов
/// </summary>
/// <param name="context">HTTP контекст запроса</param>
/// <param name="session">Сессия Web пользователя. Используйте session.User == null, если пользователь не известен.</param>
public override bool HandleWebRequest( HttpListenerContext context, WebUserSession session )
{
    HttpListenerRequest request = context.Request;
    HttpListenerResponse response = context.Response;
    var url = context.Request.Url;
    var mes = String.Format( "WEB: {0}://{1}; {2}; {3}; {4}\r\n", 
        url.Scheme, url.Host, url.AbsolutePath, 
        request.RemoteEndPoint, 
        session.User.SafeToString() );
    Service.WriteToServerLog( null, "HTTP", mes );

    return false;
}
/// <summary>
/// Пост обработчик веб запросов. Вызывается сразу после ответа на веб запрос.
/// Может использоваться для логгирования и ведения статистики обслуживания веб запросов.
/// </summary>
/// <param name="context">HTTP контекст запроса</param>
/// <param name="session">Сессия Web пользователя. Используйте session.User == null для проверки, известен ли пользователь.</param>
/// <remarks>Обработчики вызываются в порядке по возрастанию поля "Сортировка".</remarks>
public override void PostHandleWebRequest( HttpListenerContext context, WebUserSession session )
{
    HttpListenerRequest request = context.Request;
    HttpListenerResponse response = context.Response;
    if( response.StatusCode == 200 )
        return;
    var url = context.Request.Url;
    var mes = String.Format( "WEB*: {0}://{1}; {2}; {3}; {4}; {5}; \"{6}\"\r\n", 
        url.Scheme, url.Host, url.AbsolutePath, 
        session.RemoteEndPoint, 
        session.User.SafeToString(),
        response.StatusCode, response.StatusDescription
        );
    Service.WriteToServerLog( null, "HTTP", mes );
}
Обработчик HandleWebRequest в этом скрипте возвращает false, чтобы могли сработать прочие обработчики, которые собственно и формируют ответ на http запрос. Соответственно порядок скриптового действия должен быть настроен (см. поле Сортировка) так, чтобы скриптовое действие журналирования выполнялось бы до настоящих обработчиков веб запросов.

Запрос данных у сервера через HTTP
Одним из применений веб доступа к серверу БИС "Програмсоюз" является реализация простого механизма технического обмена данными между информационными системами. В ответ на HTTP/HTTPS запрос по определённому URL и комбинации параметров код кастомизации может сформировать необходимый пакет данных, например, в виде XML. Код кастомизации  скриптовой задачи вида "Серверный HTTP обработчик" может быть устроен примерно так:
/// <summary>
/// Обработчик веб запросов. Выполняется в серверных потоках-обработчиках сетевых запросов
/// </summary>
/// <param name="context">HTTP контекст запроса</param>
/// <param name="session">Сессия Web пользователя. session.User может быть null, если пользователь не известен.</param>
public override bool HandleWebRequest( HttpListenerContext context, WebUserSession session )
{
  HttpListenerRequest request = context.Request;
  HttpListenerResponse response = context.Response;
  // При необходимости код может позаботиться об аутентификации и авторизации доступа    
  //if( session.User == null )
  //    return false;
  // Запрошенный URL. Нас интересует URL вида /GetXml?id=IO.123 или /GetXml?id=C.12345
  var localUrl = request.Url.LocalPath;
  switch( localUrl )
  {
    case "/GetXml":
    {
       String idText = null;
       // Пример обработки POST запроса 
       if (request.HttpMethod == "POST" && request.HasEntityBody)
       {
          string queryString;
          using (var reader = new StreamReader(request.InputStream, request.ContentEncoding))
            queryString = reader.ReadToEnd();
          System.Collections.Specialized.NameValueCollection POST = HttpUtility.ParseQueryString(queryString);
          if(!POST["id"].IsEmpty())
            idText= POST["id"];
       }

       if( idText.IsEmpty() )
          idText = request.QueryString[ "id" ];

       DataObjectIdentifier id;
       if( DataObjectIdentifier.TryParse( idText, out id ) )
       {
          var o = Service.GetObject( id.Entity, id.Id, true ) as AttributableObject;
          if( o != null )
          {
             // Формируем XML документ с запрошенными данными, вызвав соответствующую функцию из кода кастомизации
             XmlDocument doc = ExportObjectToXML( o );
             var w = new StringWriter();
             doc.Save( w );
             // Полученный XML текст отправляем в качестве ответа на запрос
             byte[] buffer = Encoding.UTF8.GetBytes( w.ToString() );
             response.ContentLength64 = buffer.Length;
             response.ContentEncoding = Encoding.UTF8;
             response.ContentType = "text/xml";
             response.Close( buffer, true );
             // Возвращаем true, чтобы обозначить, что запрос обработан полностью
             return true;
          }
        }
        break;
     }
  }
  // false означает, что поиск обработчика для ответа на URL будет продолжен
  return false;
}
/// <summary>
/// Формирование XML данных по объекту
/// </summary>
static XmlDocument ExportObjectToXML( AttributableObject obj )
{
  var doc = new XmlDocument();
  var root = doc.CreateNode( XmlNodeType.Element, "root", String.Empty );
  doc.AppendChild( root );
  var objectNode = doc.CreateNode( XmlNodeType.Element, obj.Entity.ToString(), String.Empty );
  var nodeAttr = doc.CreateAttribute( "Id" );
  nodeAttr.Value = obj.Id.ToString( CultureInfo.InvariantCulture );
  objectNode.Attributes.Append( nodeAttr );
  nodeAttr = doc.CreateAttribute( "Name" );
  nodeAttr.Value = obj.ToString();
  objectNode.Attributes.Append( nodeAttr );
  root.AppendChild( objectNode );
  return doc;
}
Пример http запроса на клиентской стороне
public void GetXMLByHttp()
{
