  }
  catch( Exception ex )
  {
    Service.HandleException( ex, "Что-то пошло не так" );
  }
  finally
  {
    ServicePointManager.ServerCertificateValidationCallback -= ValidateRemoteCertificate;
  }
}
private static bool ValidateRemoteCertificate( object sender, X509Certificate cert, X509Chain chain, SslPolicyErrors error )
{
  if( error == SslPolicyErrors.RemoteCertificateNotAvailable )
    return false;
  if( error == SslPolicyErrors.None )
    return true;
  // Разрешаем ошибки сертификатов, чтобы код мог работать с самовыпущенными сертификатами
  return true;
}

Пример асинхронной обработки веб запросов
Сделать асинхронное получение данных на веб, очень просто.
В контроллере Default сделаем метод для получения данных для использования на веб шаблоне:
[AuthUser]
public ActionResponse SearchHeading()
{
    var result = new List<AttributableObject>();
    EntityIdentifier type = EntityIdentifier.InfoObject;
    var searchOperation = new SearchOperation(EntityIdentifier.InfoObject);
    var template1 = Service.GetTemplate(AttributableEntityIdentifier.InfoObject, @"InfoObjects\NTD");
    SearchExpressionItem rootItem;
    SearchExpressionItem subItem;
    {
        var templateFilter1 = new SearchTemplateFilterItem();
        templateFilter1.FilterByTemplate = template1;
        templateFilter1.IncludeInherited = true;
        {
            var andOp2 = new LogicalAndOperationItem(templateFilter1);
            {
                var objFilter3 = new SearchInfoObjectFilterItem(andOp2);
                objFilter3.PropertyId = SearchConditionFilterItem.SystemPropertyId.DateModified;
                objFilter3.OperatorId = RelationalOperator.LastMonth;
                objFilter3.Argument1 = DateTime.MinValue;
            }
        }
        rootItem = templateFilter1;
    }
    searchOperation.SearchExpressionTree = rootItem;
    searchOperation.Execute(false);
    var foundIO = searchOperation.FoundObjects.ToArray();
    result.AddRange(foundIO);
    result = WebHelpers.FilterVisible<AttributableObject>(result, Session.User).ToList();
    var searchResult = new List<SearchResult>();
    foreach (var item in result)
    {
        searchResult.Add(new SearchResult(item));
    }
    var pager = new WebHelpers.Paginator<SearchResult>(searchResult, Context.Request.Url, 10, "p");
    return Render(HttpStatusCode.OK, "application/json", WebJson.ToJson(new
    {
        pager = pager,
    }));
}




