UICommand.IsInvokeOnDoubleClick;

// Собственное значения без учёта применённых модификаторов или наследования
( UICommand.FlagsNonModified & UICommandBase.BitFlags.InvokeOnDoubleClick) != 0

Значок
Иконка UI команды (а так же объектного события, так как событие это подтип UI команды).
Иконка подлежит модификации и переопределению при наследовании. Для переопределения  следует снять наследование "Иконка".
Скриптовой доступ:
UICommand.Icon // Возвращает модифицированную или унаследованную иконку, устанавливает собственную иконку.
UICommand.IconNonModified // Возвращает собственную иконку.
UICommand.DisplayIcon // То же, что Icon.
У команды может быть не установлена собственная иконка, вместо неё используется унаследованная. По умолчанию UICommand.Icon и UICommand.DisplayIcon возвращает null. В этом случае используется иконка по умолчанию уровня БИС.
Иконка UI команды может формироваться динамически в обработчике UpdateState, который вызывается всякий раз, когда системе требуется проверить текущее состояние команды и её доступность для выполнения. В следующем примере UI команда действует как переключатель режима перемещения, устанавливая текст кнопки и иконку в соответствии с текущим значением вспомогательного атрибута:
/// <summary>
/// Обновление состояния элементов интерфейса в соответствие с текущим состоянием объекта
/// </summary>
/// <param name="obj">Выделенный объект,к которому потенциально может быть применена команда</param>
/// <param name="cmdUI">Объект для управления контролом вызова команды</param>
public override void UpdateState( InfoObject obj, ICmdUI cmdUI )
{
    var moveWithChildren = obj.GetValue<Boolean>("MoveWithChildren");
    // Устанавливаем ключ изображения в системном ImageList
    cmdUI.ImageKey = Service.UI.ImageListManager.GetCustomIconImageKey(
         Service.GetIcon(moveWithChildren ? "MoveWithChildren" : "MoveWithoutChildren"));
    cmdUI.Text = moveWithChildren ? "Перемещать с детьми" : "Перемещать без детей";
    cmdUI.Enabled = true;
}

/// <summary>
/// Выполнение команды над указанным объектом
/// </summary>
/// <param name="obj">Объект, к которому следует применить команду</param>
public override void Invoke( InfoObject obj )
{
    obj["MoveWithChildren"] = !obj.GetBoolean("MoveWithChildren");
}

Назначение
Подтип команды (или события объекта), определяющий конкретную разновидность объекта и сигнатуры его обработчиков кастомизации. Имеются три варианта UI команды, отличающиеся способом применения и сигнатурами обработчиков кастомизации:
Команда для одиночного объекта;
Команда для нескольких объектов;
Команда для атрибута объекта.
Дополнительно указываются: ключ атрибута, к которому прицеплена команда, и тип данных атрибута.
Кроме того, UI команды специального подтипа UICommandBase.KindEnum.ObjectEvent определяют события объекта, доступные пользователю для подписки.
Скриптовой доступ:
UICommandBase.KindEnum UICommand.Kind // Возвращает модифицированное значение, устанавливает собственное.
UICommand.KindNonModified // Возвращает собственное значение. 

enum UICommandBase.KindEnum: byte
{
   Undefined = 0,
   /// <summary>
   /// Команда для одиночного объекта
   /// </summary>
   SingleObjectCommand,
   /// <summary>
   /// Команда для нескольких выделенных объектов
   /// </summary>
   MultipleObjectCommand,
   /// <summary>
   /// Команда для атрибута объекта
   /// </summary>
   AttributeCommand,
   /// <summary>
   /// Событие объекта
   /// </summary>
   ObjectEvent,
}
В модификаторе или наследнике не переопределяется. Всегда используется унаследованное значение, если есть предшественник.

Показывать в контекстном меню
Если установлено, то команда добавляется в контекстное меню объекта.
Для переопределения в модификаторе или наследнике следует снять галочку "Флаги".
