Подготовка редактора атрибута (PrepareEditor)
void PrepareEditor( TObject obj, AttributeEditorProps editorProps ) // На уровне атрибута
bool PrepareEditor( TObject obj, AttributeDef def, AttributeDefCustomizationBase.AttributeEditorProps editorProps ) // На уровне шаблона
// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement, PrototypeObject, TaskDiagramNode

public class AttributeEditorProps
{
  /// <summary>
  /// Текст метки редактора атрибута
  /// </summary>
  public String LabelText;
}
Обработчик вызывается в коде показа окна свойств объекта при создании редакторов атрибутов. С его помощью можно программно установить метку атрибута. По умолчанию используется метка, заданная в определении атрибута.
editorProps.LabelText = "метка атрибута";
Для списковых атрибутов этот обработчик вызывается для колонки грида. Установка метка позволяет программно установить нужный заголовок колонки грида.
Сначала вызываются обработчики уровня шаблона, затем обработчики уровня атрибута. Обработчики шаблона вызываются в порядке модификаторы-дети-родители до тех пор, пока кто-нибудь не вернёт true. Если в обработчике уровня шаблона возвращается значение true, то другие обработчики не вызываются.  Обработчики уровня атрибута вызываются в порядке от предшественников к детям и модификаторам.
Примечание: Для программной настройки других параметров отображения используется обработчик PrepareDisplayParams.

Поддержка поиска для вычисляемого атрибута (ResolveAttributeSearchItem)
bool ResolveAttributeSearchItem( AttributeDef attr, SearchAttributeCriterionItem searchItem ) // На уровне шаблона и атрибута
Вычисляемые атрибуты (и простые и вычисляемые ссылки на атрибуты) обычно могут использоваться в поиске по базе только в том случае, если у них установлен режим хранимого значения. Однако в некоторых случаях в зависимости от способа вычисления атрибута можно формальным образом программно корректировать дерево поискового запроса так, чтобы пользователь мог использовать вычисляемый атрибут в поисковом запросе, но по факту поисковый запрос строился бы по тем атрибутам, которые использованы в коде вычисления атрибута.
Если обработчик возвращает true, то считается что поиск по атрибуту поддерживается и другие обработчики вызывать не следует. Вызов обработчиков происходит в порядке модификаторы-дочерние-предшественники до тех пор, пока кто-нибудь не вернёт true. Сначала вызываются обработчики уровня шаблона, затем обработчики уровня атрибута.
Вызов обработчика производится в коде конструктора поискового выражения для определения, поддерживается ли поиск по данному вычисляемому атрибуту. Важно: В этом случае параметр searchItem == null.
Основной вызов обработчика происходит в коде подготовки поискового дерева. Метод получает элемент дерева с критерием на данный атрибут. Задача скриптового кода преобразовать элемент так, чтобы он соответствовал фактически хранимым атрибутам и поисковый запрос мог бы выполниться.
Например, вычисляемый атрибут, возвращающий такой же атрибут у объекта по ссылке LinkToIO. Пользователь сформировал поисковый запрос с использованием вычисляемого атрибута. Данный обработчик заменяет этот элемент на условие на объект к атрибуту LinkToIO, и к этому условию переприцепляет переданный searchItem.
Таким образом условие на вычисляемый атрибут, заменяется в поисковом дереве на условие на атрибут LinkToIO и его хранимый атрибут, использованный в вычислении атрибута.
Код вычисления мог бы быть, например, такой:
public override bool Calculate( InfoObject obj, EntityAttribute attr )
{
  var target = obj.GetInfoObject("LinkToIO");
  attr.SetValue( target != null ? target[attr.NameKey] : null );
  return true;
}
Код коррекции поискового дерева для такого атрибута может выглядеть так:
/// <summary>
/// Модифицирует поисковое дерево для выполнения запроса по атрибуту с типом "ссылка на другой атрибут"
/// </summary>
/// <param name="attr">Определение атрибута-ссылки</param>
/// <param name="searchItem">На сервере - элемент поискового дерева, который следует модифицировать в соответствии
/// с определением ссылки на атрибут другого объекта. На клиенте - null</param>
/// <returns>true если метод реализован и поиск поддерживается. Если метод возвращает false, то поиск
/// по этому атрибуту считается нереализованным.</returns>
/// <remarks>Обычно в этом методе следует вставить поисковый элемент на атрибут-ссылку на другой объект, а 
/// существующий элемент переприцепить к нему в виде подзапроса</remarks>
public override bool ResolveAttributeSearchItem( AttributeDef attr, SearchAttributeCriterionItem searchItem )
{
 if( searchItem == null )
  // Следует вернуть true, если логика атрибута позволяется модифицировать поисковый запрос для корректного серверного поиска
  // Если вернуть false, то поиск будет считаться не реализованным. В конструкторе поисковых запросов такой атрибут не появится,
  // а его программное использование в поисковых запросах приведет к исключению
  return true;

 // Пример для случая, когда атрибут перенесен из объекта по ссылке
 // Встраиваем новый поисковый элемент - условие на атрибут-ссылку на другой объект
 var s = new SearchAttributeCriterionItem( searchItem.Parent );
 // Имеющуюся подветку перенесём в новый элемент в виде подзапроса к другому объекту
 searchItem.Parent = null;
 // Дочерние элементы, если были, перенесём дочерними к новому элементу
 // Так как они относятся к исходному объекту
 foreach( var child in searchItem.Children )
  s.Children.Add( child );
 searchItem.Children.Clear();
 s.Attribute = attr.Parent.GetAttributeDef( "LinkToIO" );
 s.OperatorId = RelationalOperator.Condition;
 s.Argument1 = searchItem;
 // У исходного элемента заменим определение атрибута, на соответствующее из шаблона другого объекта
 // В любом случае исходный элемент в неизмененном виде не должен остаться в дереве запроса.
 // Это приведет к рекурсии и исключению (глубина рекурсии 32)
 searchItem.Attribute = s.Attribute.SubItemTemplate.GetAttributeDef( attr.NameKey );
 return true;
}

Получение значения вспомогательного атрибута (GetValue)
bool GetValue( TObject obj, AttributeValue valueWrapper, out Object value )
bool SetValue( TObject obj, AttributeValue valueWrapper, Object newValue )
// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement, PrototypeObject, TaskDiagramNode
Для вспомогательных атрибутов эти обработчики позволяют переопределить логику получения/установки значения. Вызов обработчика производится скриптовым кодом, запрашивающим значение атрибута, в том числе и при показе свойств объекта в пользовательском интерфейсе.
Если обработчик возвращает true, то значение считается определённым и обработчики предшественников далее не вызываются.
Обработчик может использоваться для создания промежуточного атрибута для представления пользователю преобразованных данных при том, что реальное значение хранится в другом атрибуте, в другом объекте или ещё где-нибудь.
Оба обработчика могут использовать собственный valueWrapper как место "хранения" значения, тем самым воспроизведя логику обычного вспомогательного атрибута.
Использование SetValue/GetValue для списковых атрибутов
Эти обработчики могут использоваться и для списковых атрибутов, и множеств. В этом случае в GetValue в качестве valuе следует использовать массив соответствующих объектов. Например:
public override bool GetValue( InfoObject obj, AttributeValue valueWrapper, out object value )
{
  //var def = ( AttributeDef )Owner;
  value = obj.GetCollectionElements("List").ToArray();
  return true;
}
Параметр valueWrapper для списковых атрибутов не используется (в обработчик передаётся null).
Примечание: для атрибутов типа множество, коллекция элементов и композитных имеются разные скриптовые способы редактирования значения. Например, добавление элемента коллекции - это операция надо уже имеющимся "значением" в виде коллекции элементов. Такие изменения не приводят к вызову кастомизатора SetValue. Однако при присваивании значения через методы, принимающие Object, этот вызов происходит:
attr.SetValue( <массив> );
attr.Value.Value = <массив>;
obj["список или множество"] = <массив>;
В пользовательском интерфейсе клиентского приложения обработчик SetValue для списковых атрибутов вызывается лишь при попытке сохранения объекта, у которого вспомогательный списковый атрибут помечен как изменённый. То есть внутри вызова obj.Save или Service.SaveChanges происходит проверка всех изменённых вспомогательных списковых атрибутов в сохраняемых объектах, и для них вызывается обработчик SetValue. Признак изменённости для вспомогательного атрибута требует "ручного управления". Скриптовой код должен сам когда-то поставить вспомогательному атрибуту изменённое состояние. Это можно сделать например таким кодом в определении спискового атрибута:
public override void OnAttributeChanged( InfoObject obj, EntityAttribute attr )
{
 // Изменения атрибутов в ходе обработки операции сохранения или просто на сервере
 // обычно не требуют дополнительной обработки. завершаем метод в этом случае.
    if( Service.IsInSaveProcessing || Service.RunningOnServer || Service.IsImportOperation )
        return;

    attr.MarkDirty();    
    obj.MarkDirty();
}
Обработчик OnAttributeChanged сработает, когда пользователь изменит что-либо в атрибуте. Сохранение объекта после этого приведёт к вызову обработчика SetValue, код которого обработает сделанные изменения для сохранения их в других атрибутах/объектах.

Проверка значения при вводе (ValidateInput)
string ValidateInput( TObject obj, TAttribute attr, ref Object newValue )

// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement, PrototypeObject, TaskDiagramNode
Этот обработчик используется проверки вводимого значения. Он вызывается в коде присваивания нового значения атрибуту (кроме присваивания внутри обработчика Calculate). Для текстовых атрибутов этот обработчик может вызываться при вводе каждого символа.
Примечание: Применяется только для простых атрибутов (те, значения которых устанавливается через AttributeValue.Value). Для списковых, композитных атрибутов и множеств не вызывается.
Обработчик может:
подправить вводимое значение, изменив параметр newValue;
вернуть сообщение о проблеме, которое появится рядом с атрибутом в виде красного значка.
сгенерировать программное исключение, текст которого так же появится рядом с атрибутом в виде красного значка.
Вызывается как на сервере так и на клиенте - по месту присвоения значения атрибута. Вызов обработчиков происходит в порядке модификаторы-дети-предшественники до тех пор, пока кто-нибудь не вернёт не null.
Примечание: При подмене вводимого значения "на лету" чтобы это изменение отразилось в пользовательском интерфейсе, следует "сообщить" ему о таком изменении при помощи вызова: attr.RefreshUI(). При этом редактор атрибута перезачитает значение для отображения (выделение и позиция каретки будет утеряна).
Пример
Ниже приведён обработчик атрибута "С", содержащего начальное время суток в записях календаря. Код, проверяющий введённый текст, выдаёт сообщение пользователю в виде красного шарика:
/// <summary>
/// Проверка значения атрибута во время ввода. Возвращает сообщение об ошибке либо null.
/// Вызывается из сеттера AttributeValue.Value. Исключения при этом перехватываются и 
/// трактуются как сообщения об ошибке.
/// </summary>
/// <param name="obj">Объект, чей атрибут проверяем</param>
/// <param name="attr">Собственно атрибут</param>
/// <param name="newValue">Новое значение, которое собираемся присвоить атрибуту</param>
/// <returns>null, если все хорошо, либо сообщение об ошибке</returns>
public override string ValidateInput( CollectionElement obj, SubItemAttribute attr, Object newValue )
{
    var tempHourFrom = newValue as String; // время "С"    
    if (tempHourFrom == null || tempHourFrom.Length != 4)
        return "Неверный формат времени";

    int hourFrom = 0;
    if (!int.TryParse(tempHourFrom.Substring(0, 2), out hourFrom))
        return "Неверный формат времени";
    int minuteFrom = 0;
    if (!int.TryParse(tempHourFrom.Substring(2, 2), out minuteFrom))
        return "Неверный формат времени";

    if (minuteFrom > 59)
        return "Неверный формат времени";

    if (( hourFrom == 24 && minuteFrom > 0 ) || ( hourFrom > 24 ))
        return "Неверный формат времени";

    return null;
}
Вот так выглядит результат работы этого метода для пользователя:

Серверная проверка атрибутов перед сохранением (Validate)
Применяется для шаблонов атрибутируемых объектов и элементов коллекций.
string Validate( TObject obj ) // на уровне шаблона
string Validate( TObject obj, TAttribute attr ) // на уровне определения атрибута
// TObject заменяется на конкретный тип объекта: 
// InfoObject, DataContainer, User, Task, WorkItem, CollectionElement;
// TAttribute заменяется на EntityAttribute или SubItemAttribute для элемента коллекции.
Этот метод вызывается на сервере в начале серверной операции сохранения для всех, вовлечённых в операцию объектов. А так же для изменённых элементов коллекций в списковых атрибутах новых или изменяемых объектов.
Для изменённых атрибутов вызывается обработчик уровня определения атрибута.
Для проверки объекта на клиенте и в особенности для проверки нехранимого объекта можно использовать обработчик OnBeforeSaveInUI.

Создание пользовательского редактора (CreateAttributeEditor)
Control CreateAttributeEditor( TObject obj, TAttribute attr, object dataSource, 
        BindingCompleteEventHandler bindingComplete, AttributeDefBase.CustomEditorParams editorParams )

// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement, PrototypeObject, TaskDiagramNode
Этот обработчик используется для формируемых скриптом редакторов атрибутов, если для атрибута установлен Вариант отображения "пользовательский редактор". Параметр dataSource с ключом attr.NameKey можно использовать для привязки значения атрибута к содержимому, отображаемому пользовательским редактором.
Вызов обработчиков происходит в порядке модификаторы-дети-родители до тех пор, пока кто-нибудь не вернёт не null.
Например, для атрибута типа "бинарные данные" отсутствует какой-либо штатный редактор для представления его в окне свойств объекта. В качестве значения атрибут этого типа хранит массив байтов. Следующий код формирует для него пользовательский редактор, который в поле ввода показывает размер массива:
/// <summary>
/// Вызывается клиентским кодом UI для создания собственного редактора атрибута на карточке объекта.
/// </summary>
/// <param name="obj">Объект, чья карточка показывается</param>
/// <param name="attr">Атрибут, для которого создается редактор</param>
/// <param name="dataSource">Источник данных для привязки контрола к данным</param>
/// <param name="bindingComplete">Обработчик завершения привязки данных</param>
/// <param name="editorParams">Параметры для контрола</param>
/// <remarks>Вызывается на клиентской стороне при использовании штатных карточек атрибутируемых объектов.
/// Исключения, вышедшие их этого метода, отправляются в серверный отчет об ошибке без показа сообщения пользователю.</remarks>
public override Control CreateAttributeEditor( InfoObject obj, EntityAttribute attr, object dataSource, 
         BindingCompleteEventHandler bindingComplete, AttributeDefBase.CustomEditorParams editorParams )
{
    var box = new TextBox();
    box.ReadOnly = true;

    var binding = box.DataBindings.Add( "Text", dataSource, attr.NameKey, true, DataSourceUpdateMode.Never );
    binding.Format += ( sender, args ) => 
        { 
            if( args.Value is byte[] )
            {
                var bytes = (byte[])args.Value;
                args.Value = "<" + bytes.Length + " байт>";
            }
            else
                args.Value = args.Value.SafeToString(); 
        };

    return box;
}
В случае, когда обработчик определён на вычисляемом по ссылке атрибуте (прокси-атрибуте), то следует иметь в виду, что attr может быть атрибутом другого объекта, в соответствии с логикой обработчика ResolveAttribute. При этом obj - это объект, для которого формируется окно свойств и сам кастомизатор вызывается в определении прокси атрибута, а не в определении фактического атрибута.
Примечание: это поведение было поправлено, начиная с версии: 3.1.0.322.

Сравнение атрибутируемых объектов по атрибуту (Compare)
Применяется для шаблонов атрибутируемых объектов и элементов коллекций
int? Compare( AttributeDef def, IAttributableObject obj1, IAttributableObject obj2 )
Обработчик вызывается в штатном коде сравнения объектов по атрибуту для кастомизации сравнения или реализации более сложного сравнения например по нескольким атрибутам. Сначала вызывается обработчик шаблона левого операнда (obj1), затем правого операнда (obj2), затем обработчик определения атрибута (def), пока кто-нибудь не вернёт не null. Если обработчик не определился со сравнением, то сработает штатный код сравнения по значению атрибута.
В клиентском приложении сортировка применяется для определения порядка объектов в дереве всего хранилища, в списках объектов, в гридах списковых атрибутов.
Сортировка объектов в дереве сначала упорядочивает объекты по порядку закладок-фильтров, к которым отнесены эти объекты в правилах вложения, далее они упорядочиваются по тому атрибуту и параметрам сортировки, которые заданы в закладке-фильтре. В ходе сортировки по атрибуту вызывается этот кастомизатор.
В списках объекты сортируются по выбранной пользователем колонке и если в ней отображаются значения атрибута, то для него вызывается и этот кастомизатор сравнения.
В списковых атрибутов при отображении строк грида в зависимости от настроек шаблона строки списка применяется либо сортировка по предустановленному в шаблоне атрибуту, либо по выбранной пользователем колонке с вызовом соответствующего кастомизатора.
Скриптовое использование
Чтобы упорядочить объекты скриптом так, как это делает клиентское приложения, можно использовать следующие способы:
// Сортировка как в дереве с учётом настроек закладок-фильтров:
obj.RootInfoObjects.OrderBy( o => o, new AttributableObjectChildComparer( obj ) )
// Сортировка коллекции или атрибутируемых объектов по атрибуту:
var defName = listAttribute.SubItemTemplate.GetAttributeDef("Name");
var defOrdinal = listAttribute.SubItemTemplate.GetAttributeDef("Ordinal");
listAttribute.OrderBy(defOrdinal).ThenByDescending( defName );
// Получение сортированной коллекции в соответствии с настройками её шаблона
listAttribute.GetCollectionElementsSorted();
obj.GetCollectionElementsSorted("ListAttribute");
Если требуется переопределить сортировку по атрибуту так, чтобы работал кастомизатор другого атрибута, можно переадресовать вызов при помощи метода:
attributeDef.InvokeCompare( obj1, obj2 );
или явно сравнить два объекта с использованием кастомизации:
var result = attributeDef.CompareObjects( obj1, obj2 );

Уведомление об изменении значения атрибута (OnAttributeChanged)
После присвоения атрибуту нового значения происходит вызов обработчика кастомизации:
string void OnAttributeChanged( TObject obj, TAttribute attr )
// Одинаковая сигнатура как для уровня шаблона, так и для уровня определения атрибута.
// TObject заменяется на конкретный тип объекта: InfoObject, DataContainer, User, CollectionElement и т.п.
// TAttribute заменяется на конкретный тип атрибута: EntityAttribute для атрибутов верхнего уровня или SubItemAttribute
// для атрибутов элементов коллекций
Его код может проверить или изменить другие атрибуты объекта на основании нового значения.
Вызывается как на сервере так и на клиенте - по месту присвоения значения атрибута. Обработчики кастомизации атрибута и его предшественников вызываются в порядке родители-дети-модификаторы, сначала для шаблонов, затем для атрибутов.
Примечание: при вызове обработчика на уровне шаблона, параметр attr может быть null. Это происходит при обновлении объекта целиком. Код кастомизации должен учитывать такую возможность.
Важно: Начиная с версии 3.2.7.495, исключения в этом методе перехватываются и отправляются в серверный репорт. При этом если обработчик вызван для отображаемого в пользовательском интерфейсе объекта, то текст исключения появится рядом с редактором атрибута в виде красного шарика с всплывающей подсказкой. В предыдущих версиях исключения подавлялись в случае показа объекта в интерфейсе и не подавлялись при других способах изменения атрибутов.
Технически исключения в этом обработчике не могут использоваться для отмены внесённых изменений, так как значение атрибута уже изменено на момент вызова, и сам обработчик вызывается внутри внутреннего кода обновления скриптовой оболочки по состоявшимся изменениям.
Примечание: обработчики на уровне атрибута фактически вызываются от детей-модификаторов к предшественникам, но при этом вызывается сигнатура метода с третьим параметром out bool handled, которую можно использовать для прерывания последующих вызовов обработчиков в цепочке. Реализация обработчика по умолчанию вызывает обработчик без третьего параметра.
Пример
Строка автозадачи этапа процесса WorkFlow при выборе того или иного вида автозадачи переустанавливает некоторые свои атрибуты:
/// <summary>
/// Нотификация об изменении какого-либо атрибута объекта
/// </summary>
/// <param name="obj">Объект, чей атрибут изменился</param>
/// <param name="attr">Собственно изменившийся атрибут либо null, если изменилось сразу много атрибутов</param>
public override void OnAttributeChanged( CollectionElement obj, SubItemAttribute attr )
{
    if( attr != null && attr.NameKey == "Kind" )
    {
        var kind = obj.GetValue< NamedValue >( "Kind" );
        if( kind == null ||
            !(
                 kind.ValueAsString == "ByTimer" ||
                 kind.ValueAsString == "OnNodePassed" ||
                 kind.ValueAsString == "OnWorkItemClosed" ||
                 kind.ValueAsString == "OnNodeActivatedAndPassed" ||
                 kind.ValueAsString == "BeforeWorkItemClosedOnClient"
             ) )
            obj[ "InvokeOn" ] = null;
        else if( kind.ValueAsString == "ByTimer" )
            obj[ "InvokeOn" ] = String.Empty;
        if( kind != null && kind.ValueAsString == "PrestartCheck" )
            obj[ "ObjectsToHandle" ] = "StartObjects";

        var actionAttr = obj.GetAttribute( "AutoActionKey" );
        var actionKey = actionAttr.Value.GetValue<String>();
        if( !actionKey.IsEmpty() )
        {
            var root = actionAttr.GetNamedValueRange();
            var nv = root.AllChildren.FirstOrDefault( o => o.ValueAsString == actionKey );
            if( nv == null )
                obj[ "AutoActionKey" ] = null;
        }
    }
}

Управление видимостью атрибута (IsAttributeVisibleInUI)
bool? IsAttributeVisibleInUI( TObject obj ) // На уровне атрибута
bool? IsAttributeVisibleInUI( TObject obj, AttributeDef def ) // На уровне шаблона
// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement, PrototypeObject, TaskDiagramNode
Обработчик определяет является ли атрибут скрытым или видимым в пользовательском интерфейсе стандартной карточки.  В качестве параметра принимает фактический объект, чей атрибут нужно проверять. Если обработчик определён на уровне шаблона, то передаётся и определение проверяемого атрибута.
Если в обработчике возвращается значение true, то означает, что атрибут виден, false - скрыт. Возврат null означает, что данный обработчик не может определить состояние атрибута и следует продолжить вызов прочих обработчиков. Вызов их происходит в порядке модификаторы-дети-родители до тех пор, пока кто-нибудь не вернёт не null. Сначала вызываются обработчики уровня шаблона, затем обработчики уровня атрибута.
Вызов обработчика производится кодом показа стандартной карточки объекта при каждом изменении чего-либо в объекте. Обычное его применение - это управление видимостью редактора атрибута в зависимости от значений прочих атрибутов объекта.

Установка значения вспомогательного атрибута (SetValue)
bool GetValue( TObject obj, AttributeValue valueWrapper, out Object value )
bool SetValue( TObject obj, AttributeValue valueWrapper, Object newValue )
// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement, PrototypeObject, TaskDiagramNode
Для вспомогательных атрибутов эти обработчики позволяют переопределить логику получения/установки значения. Вызов обработчика производится скриптовым кодом, запрашивающим значение атрибута, в том числе и при показе свойств объекта в пользовательском интерфейсе.
Если обработчик возвращает true, то значение считается определённым и обработчики предшественников далее не вызываются.
Обработчик может использоваться для создания промежуточного атрибута для представления пользователю преобразованных данных при том, что реальное значение хранится в другом атрибуте, в другом объекте или ещё где-нибудь.
Оба обработчика могут использовать собственный valueWrapper как место "хранения" значения, тем самым воспроизведя логику обычного вспомогательного атрибута.
Использование SetValue/GetValue для списковых атрибутов
Эти обработчики могут использоваться и для списковых атрибутов, и множеств. В этом случае в GetValue в качестве valuе следует использовать массив соответствующих объектов. Например:
public override bool GetValue( InfoObject obj, AttributeValue valueWrapper, out object value )
{
  //var def = ( AttributeDef )Owner;
  value = obj.GetCollectionElements("List").ToArray();
  return true;
}
Параметр valueWrapper для списковых атрибутов не используется (в обработчик передаётся null).
Примечание: для атрибутов типа множество, коллекция элементов и композитных имеются разные скриптовые способы редактирования значения. Например, добавление элемента коллекции - это операция надо уже имеющимся "значением" в виде коллекции элементов. Такие изменения не приводят к вызову кастомизатора SetValue. Однако при присваивании значения через методы, принимающие Object, этот вызов происходит:
attr.SetValue( <массив> );
attr.Value.Value = <массив>;
obj["список или множество"] = <массив>;
В пользовательском интерфейсе клиентского приложения обработчик SetValue для списковых атрибутов вызывается лишь при попытке сохранения объекта, у которого вспомогательный списковый атрибут помечен как изменённый. То есть внутри вызова obj.Save или Service.SaveChanges происходит проверка всех изменённых вспомогательных списковых атрибутов в сохраняемых объектах, и для них вызывается обработчик SetValue. Признак изменённости для вспомогательного атрибута требует "ручного управления". Скриптовой код должен сам когда-то поставить вспомогательному атрибуту изменённое состояние. Это можно сделать например таким кодом в определении спискового атрибута:
public override void OnAttributeChanged( InfoObject obj, EntityAttribute attr )
{
 // Изменения атрибутов в ходе обработки операции сохранения или просто на сервере
 // обычно не требуют дополнительной обработки. завершаем метод в этом случае.
    if( Service.IsInSaveProcessing || Service.RunningOnServer || Service.IsImportOperation )
        return;

    attr.MarkDirty();    
    obj.MarkDirty();
}
Обработчик OnAttributeChanged сработает, когда пользователь изменит что-либо в атрибуте. Сохранение объекта после этого приведёт к вызову обработчика SetValue, код которого обработает сделанные изменения для сохранения их в других атрибутах/объектах.

Формирование уникального значения (BuildUniquenessValue)
Применяется для шаблонов атрибутируемых объектов и элементов коллекций.
bool BuildUniquenessValue( InfoObject obj, EntityAttribute attr, ref String uniqueValue )
// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, WorkItem, 
// CollectionElement
Корректировка значения атрибута (uniqueValue), помещаемого в пространство уникальности. Возвращает true если значение успешно вычислено и обработчики предшественников вызывать не следует.
Если для определения атрибута указано пространство уникальности, то при сохранении в базу значений этого атрибута происходит и контроль уникальности. Это делается путём записи уникального значения атрибута в отдельную таблицу с составным уникальным индексом, так чтобы комбинация пространства уникальности, ключа уникальности и собственно значения была бы уникальной. Ключ уникальности вычисляется на основа подтипа пространства уникальности, а в качестве значения обычно используется текстовое представление значения атрибута. С помощью данного обработчика прикладной код может скорректировать значение, сохраняемое в таблице уникальности.
Например, если требуется обеспечить уникальность значений с учётом возможных замен похожих по начертанию русских и латинских букв, то следующим обработчиком можно обеспечить нормализацию сохраняемых уникальных значений. При этом фактическое значение сохраняется в базу как введено пользователем, а для контроля уникальности используется нормализованное значение:
/// <summary>
/// Подготовка значения атрибута для помещения в пространство уникальности. Возвращает true если значение успешно вычислено
/// </summary>
/// <param name="obj">Объект, чей атрибут готовим для уникальности</param>
/// <param name="attr">Собственно атрибут, чье значение помещается в ПУ</param>
/// <param name="uniqueValue">На входе - текущее значение, возможно уже преобразованное дочерними обработчиками.
/// На выходе значение, помещаемое в пространство уникальности</param>
/// <returns>true, если значение вычислено, false, если следует продолжить преобразование обработчиками предшественников</returns>
public override bool BuildUniquenessValue( InfoObject obj, EntityAttribute attr, ref String uniqueValue )
{
    if ( !String.IsNullOrEmpty( uniqueValue ) )
        uniqueValue = Transliteration.Normalize( uniqueValue ).Trim();

    return true;
}
Класс Transliteration берёт идентичные символы из разных языков по настройке реестра: 
Системные настройки\Транслитерация\Идентичные символы = "aAаА,oOоО,eEеЕ,cCсС,...".
В качестве нормализованного берётся заглавная латинская буква, если есть такая в группе, либо первый символ из группы.
Примечание: Есть сигнатура метода Normalize с параметром keepCase, которая позволяет нормализовать текст с учётом регистра, то есть в качестве нормализованного символа берётся первый в группе символ того же регистра.

Автоматический размер
Применяется для атрибутов элементов коллекций. Задаёт режим установки ширину колонки таблицы спискового атрибута.
Свойство подлежит модификации и переопределению при наследовании. Для переопределения  следует снять наследование "Параметры отображения колонки в списках".
Скриптовой доступ:
// Возвращает модифицированное или унаследованное значение, устанавливает собственное.
DataGridViewAutoSizeColumnMode AttributeDef.ColumnSizeMode

// Возвращает собственное значение.
AttributeDef.ColumnSizeModeNonModified
Возможные значения System.Windows.Forms.DataGridViewAutoSizeColumnMode:
// Значения ширины столбцов не изменяются автоматически.
None,

// Ширина столбца изменяется так, чтобы вместить содержимое ячейки заголовка для столбца.
ColumnHeader,

// Ширина столбца изменяется так, чтобы вместить содержимое всех ячеек столбца, за исключением ячейки заголовка.
AllCellsExceptHeader,

// Ширина столбца изменяется так, чтобы вместить содержимое всех ячеек столбца, включая ячейку заголовка.
AllCells,

// Ширина столбца изменяется так, чтобы вместить содержимое всех ячеек столбца, которые находятся в строках, отображающихся на экране в настоящий момент, за исключением строки заголовка.
DisplayedCellsExceptHeader,

// Ширина столбца изменяется так, чтобы вместить содержимое всех ячеек столбца, которые находятся в строках, 
// отображающихся на экране в настоящий момент, включая строку заголовка.
DisplayedCells,

// Ширина столбца подбирается таким образом, чтобы суммарная ширина всех столбцов в точности заполняла отображаемую область 
//элемента управления, а прокрутка по горизонтали требовалась только для столбцов, ширина которых превышает значение свойства
