Гиперссылки в форматированных текстах
В форматированных текстах (RTF, HTML) могут использовать гиперссылки как на объекты БИС "Програмсоюз", так и на внешние объекты (URL, файлы и прочее).
Скриптами кастомизации можно переопределить реакцию программы на действия с этими гиперссылками. Более того, можно специально формировать вычисляемый атрибут с HTML или RTF текстом, который бы предлагал пользователю некоторые операции в виде гиперссылок.
Для примера рассмотрим фрагмент кода формирующего список этапов, к которым перейдёт Workflow процесс после завершения текущего этапа:
// Объект для формирования HTML текста
var b = new StringBuilder();
// Часть кода пропускаем для простоты
...
// Список этапов, которые отображаются в HTML тексте
var nodes = transition.Connections.Select( id => diagram.GetLinkByGlobalIdentifier( id ) ).SkipNull().
    Select( o => o.TargetNode ).ToArray();
if( !nodes.IsEmpty() )
{
    b.Append("<br>").Append( nodes.Length == 1 ? "К этапу: " : "К этапам: " );
    var first = true;
    foreach( var node in nodes )
    {
        if( !first )
            b.Append( ", " );
        // Добавляем название этапа
        b.Append( HtmlTools.HtmlEncode( node.ToString() ) );
        var currentTask = node.CurrentTask;
        if( currentTask != null )
        {
            // Определим, может ли текущий пользователь назначать исполнителя.
            // В зависимости от этого, либо сформируем гиперссылку, либо оставим статический текст   
            var cmd = currentTask.Template.GetUICommand( "SetActor" );
            var cmdUI = new ShortcutCmdUI( "SetActor" );
            cmd.UpdateState( currentTask, cmdUI );
            var canChangeActor = cmdUI.Enabled;
            var actor = currentTask.GetValue<User>( "Actor" );
            if( actor != null )
            {
                // Если исполнитель есть, добавим на него ссылку
                if( canChangeActor )
                    // Сформируем обычную гиперссылку на пользователя-исполнителя и
                    // специальную гиперссылку "Изменить" для вызова команды смены исполнителя.
                    // Для нее используем стандартный префикс Service.UI.CustomCommandPrefix
                    b.AppendFormat( " (<a href=\"{0}\">{1}</a> | <a href=\"{2}{3}\"><font color=\"#000000\">изменить</font></a>)", Service.UI.FormatLink( actor ), HtmlTools.HtmlEncode( actor.ToString() ), Service.UI.CustomCommandPrefix, node.GlobalIdentifier.ToString() );
                else
                    // Если менять исполнителя не можем, то просто гиперссылка на исполнителя и всё
                    b.AppendFormat( " (<a href=\"{0}\">{1}</a>)", Service.UI.FormatLink( actor ), HtmlTools.HtmlEncode( actor.ToString() ) );
            }
            else
            {
                // Если исполнителя нет, то статический текст + опционально специальная ссылка с командой "Изменить".
                if( canChangeActor )
                    b.AppendFormat( " (автоназначение | <a href=\"{0}{1}\"><font color=\"#000000\">изменить</font></a>)", Service.UI.CustomCommandPrefix, node.GlobalIdentifier.ToString() );
                else
                    b.Append( " (автоназначение)" );
            }
        }

        first = false;
    }
}
// Устанавливаем атрибуту вычисленное значение
attr.SetValue( b.ToString() );
Таким образом получается HTML текст, в котором имеются гиперссылки с тегом HREF вида: "custom-command:{GUID-этапа-процесса}". Далее приведём примерный код обработчика щелчка мышкой по такой гиперссылке.
/// <summary>
/// Обработчик нажатия на гиперссылку для HTML/RTF атрибутов
/// </summary>
/// <param name="obj">Объект, которому принадлежит атрибут</param>
/// <param name="attr">Атрибут с гипертекстом</param>
/// <param name="target">Целевой объект (для ссылок на объекты PLM)</param>
/// <param name="targetUrl">URL гиперссылки (содержимое тэга HREF)</param>
/// <param name="control">true если нажата клавиша Control</param>
/// <param name="alt">true если нажата клавиша Alt</param>
/// <param name="shift">true если нажата клавиша Shift</param>
/// <param name="editMode">true если установлен режим редактирования текста</param>
/// <returns>true если действие обработано и вызов других обработчиков не требуется</returns>
public virtual bool OnHyperlink( TObject obj, TAttribute attr, ScriptingObject target, string targetUrl, bool control, bool alt, bool shift, bool editMode )
{
    // Проверим, что обработчик вызван для "нашей" специальной гиперссылки
    if( targetUrl.IsEmpty() || !targetUrl.StartsWith( Service.UI.CustomCommandPrefix ) )
        return false;
    // Завершаемая нагрузка, для которой показан диалог завершения

    var workItemId = obj.GetValue<uint>( "WorkItemId" );
    var w = Service.GetWorkItem( workItemId );
    if( w != null )
    {
        // Достаём идентификатор этапа из переданных в тэге HREF данных
        linkData = linkData.Substring( Service.UI.CustomCommandPrefix.Length );
        var nodeGuid = new Guid( linkData );
        // Вычисляем собственно этап и вызываем для него UI команды переназначения исполнителя
        var node = w.MasterTask.ParentDiagramNode.Owner.GetNodeByGlobalIdentifier( nodeGuid );
        if( node.CurrentTask != null )
        {
            node.CurrentTask.InvokeUICommand( "SetActor" );
            // Инициируем перевычисление атрибут, чтобы HTML сформировался бы заново
            // с уже обновлённым исполнителем
            attr.MarkDirty();

            // Возвращаем true - действие обработано
            return true;
        }
    }
    // Возвращаем false - действие может быть обработано другими обработчиками
    return false;
}
В дополнение к собственно обработчику щелчка можно переопределить всплывающую подсказку, которая появляется при наведении мышки на гиперссылку. Для этого используется примерно такой обработчик:
/// <summary>
/// Обработчик нажатия на гиперссылку для HTML/RTF атрибутов - формирование всплывающей подсказки для гиперссылки
/// </summary>
/// <param name="obj">Объект, которому принадлежит атрибут</param>
/// <param name="attr">Атрибут с гипертекстом</param>
/// <param name="target">Целевой объект (для ссылок на объекты PLM)</param>
/// <param name="targetUrl">URL гиперссылки (содержимое тэга HREF)</param>
/// <param name="editMode">true если установлен режим редактирования текста</param>
/// <param name="linkText">На выходе текст всплывающей подсказки</param>
/// <param name="hintText">На выходе подсказка о вариациях поведения с разными сдвиговыми клавишами.</param>
/// <returns>true если действие обработано и вызов других обработчиков не требуется</returns>
public virtual bool OnHyperlinkTooltip( TObject obj, TAttribute attr, ScriptingObject target, string targetUrl, bool editMode, out string linkText, out string hintText )
{
    linkText = null;
    hintText = null;
    var linkData = targetUrl.Safe();
    if( !linkData.StartsWith( Service.UI.CustomCommandPrefix ) )
        return false;
    linkData = linkData.Substring( Service.UI.CustomCommandPrefix.Length );
    var workItemId = obj.GetValue<uint>( "WorkItemId" );
    var w = Service.GetWorkItem( workItemId );
    if( w != null )
    {
        var nodeGuid = new Guid( linkData );
        var node = w.MasterTask.ParentDiagramNode.Owner.GetNodeByGlobalIdentifier( nodeGuid );
        if( node.CurrentTask != null )
        {
            linkText = "Назначение исполнителя этапа";
            return true;
        }
    }
    return false;
}

Доступ к скриптингу из JS внутри HTML редактора
В качестве редактора HTML текстов используется встроенный в Windows WebBrowser контрол (Microsoft Internet Explorer). Для взаимодействия с родительским приложением WebBrowser контрол поддерживает в JS объект external. Для редактора HTML атрибута через этот объект подключается выход в скриптовой слой через промежуточный COM объект. Вот пример кода формирования такого HTML:
var sb = new StringBuilder();
...
sb.Append("<button " + 
"onclick=\"external.ShowMessage( window.external.OwnerObject.InvokeTemplate('Test', 'Invoke from JS script code', 1, 2, 3, external.OwnerObject, external.OwnerObject.Container ))\">" + 
"call template invoke</button><br>" );


sb.Append( "<button " + 
"onclick=\"external.ShowMessage( external.CurrentUser + ': ' + external.OwnerObject.GetAttribute('Name') )\">" + 
"GetAttribute('Name')</button><br>" );


sb.Append( "<button " + 
"onclick=\"external.ShowMessage( window.external.OwnerObject.ShowObjectProperties() )\">" + 
"ShowObjectProperties test</button>" );
Промежуточный COM объект, доступный через external предоставляет следующие свойства и методы:
// Ключ атрибута, отображаемого HTML редактором
String AttributeNameKey {get;}


// Id объекта, чей атрибут отображается HTML редактором
ulong OwnerObjectId {get;}


// Объект, чей атрибут отображается HTML редактором
Object OwnerObject {get;}


// Вызов Invoke метода из шаблона объекта, чей атрибут отображается HTML редактором
// method - Имя метода
// args - Аргументы
// <returns>Результат Invoke-вызова</returns>
Object InvokeTemplate( String method, params Object[] args );


// Вызов экземплярного Invoke метода из объекта, чей атрибут отображается HTML редактором
// method - Имя метода
// args - Аргументы
// <returns>Результат Invoke-вызова</returns>
Object InvokeInstance( String method, params Object[] args );


// Доступ к объекту по Id
// entityId = ( EntityIdentifier )Enum.Parse( typeof( EntityIdentifier ), entity );
Object GetObject( String entity, ulong id );


// Доступ к объекту по Guid
// entityId = ( EntityIdentifier )Enum.Parse( typeof( EntityIdentifier ), entity );
Object GetObjectByGuid( String entity, Guid id );


// Доступ к объекту по пути по ключам
// entityId = ( EntityIdentifier )Enum.Parse( typeof( EntityIdentifier ), entity );
Object GetObjectByPath( String entity, String path );


// Получает значение из PLM реестра
Object GetCommonRegistryValue( String path, Object defaultValue = null );


// Получает значение из PLM реестра
Object GetUserRegistryValue( String path, Object defaultValue = null );


// Имя сервера, к которому подключены в данный момент
String ServerHostName {get;}


// Порт сервера, к которому подключены в данный момент
int ServerPortNumber {get;}


// Имя http-сервера, связанного с этим сервером PLM
String HttpServerHostName {get;}


// Серверное время, приведённое к местному локальному
DateTime ServerTime {get;}


// IP адрес и порт локальной стороны соединения. Результат следует преобразовать к IPEndPoint
String LocalEndPoint {get;}


// Версия фреймворка (по месту вызова)
String FrameWorkVersion {get;}


// Версия фреймворка, работающего на сервере
String ServerFrameWorkVersion {get;}


// Текущее "известное" состояние связи с сервером
bool IsServerConnected {get;}


// GUID центрального хранилища
String MasterServerGuid {get;}


// Технический GUID экземпляра базы. Формируется по имени сервера, имени инсталляции SQL сервера, имени базы и GUID центрального хранилища.
String DatabaseInstanceGUID {get;}


// Короткое название продукта
String ProductShortName {get;}


// Полное название продукта
String ProductFullName {get;}


// Текущий пользователь
Object CurrentUser {get;}


// Отображение окошка с сообщением (реализовано только на клиенте)
// text - Текст сообщения
// buttons - Набор кнопок
// <returns>Нажатая пользователем кнопка</returns>
String ShowMessage( string text, string buttons = null );


// Отображение окошка с сообщением (реализовано только на клиенте)
// text - Текст сообщения
// details - Текст доступный по кнопке Подробнее
// buttons - Набор кнопок
// <returns>Нажатая пользователем кнопка</returns>
String ShowMessageWithDetails( string text, string details, string buttons = null );
Параметры типа enum в JS указываются в виде строки, так чтобы методе Enum.Parse смог бы получить фактическое значение. Например в коде показа всплывающего сообщения ShowMessage используется такое преобразование:
var buttonsId = ( MessageBoxButtons )Enum.Parse( typeof( MessageBoxButtons ), buttons );
Методы могут возвращать и принимать в качестве параметров скриптовые объекты. Для существования в JS среде скриптовые объекты оборачиваются в COM обёртки: InfoObjectWrapper, UserWrapper и им подобные. Эти обёртки содержат минимальный набор свойств и методов. Подробнее можно посмотреть в PLMScripting.dll в пространстве имён: ProgramSoyuz.PLM.Scripting.COM.

Целое число (4 байта)
Тип данных атрибута для целых чисел.
Поддерживается три типа для целых чисел:
4-х байтовый числа;
8-ми байтовые числа;
числа с размерностью идентификатора. В БИСv2 - 4 байта, в БИСv3 - 8 байт.
Целое число (4 байта)
В базе хранится целое число (4 байта) в колонке IntegerNumber типа int (SQL Server и Postgres).
Скриптовой доступ:
AttributeDef.DataType == AttributeDefBase.DataTypeEnum.IntegerNumber
Получение значений атрибута:
int n = obj.GetInteger("ключ атрибута");
n = obj.GetValue<int>("ключ атрибута");
int? nOrNull = obj.GetValue<int?>("ключ атрибута");
n = obj["ключ атрибута"].GetValueOfType<int>();
n = obj.GetAttribute("ключ атрибута").Value.GetValue<int>();
Целое число (8 байт)
В базе хранится целое число (8 байт) в колонке LongNumber типа bigint (SQL Server и Postgres).
Скриптовой доступ:
AttributeDef.DataType == AttributeDefBase.DataTypeEnum.LongIntegerNumber
Получение значений атрибута:
long n = obj.GetLongInteger("ключ атрибута");
n = obj.GetValue<long>("ключ атрибута");
long? nOrNull = obj.GetValue<long?>("ключ атрибута");
n = obj["ключ атрибута"].GetValueOfType<long>();
n = obj.GetAttribute("ключ атрибута").Value.GetValue<long>();
Целое число (размерность идентификатора)
В базе хранится так же как целое число соответствующей размерности.
Скриптовой доступ:
AttributeDef.DataType == AttributeDefBase.DataTypeEnum.IdSizeIntegerNumber
При компиляции скриптов кастомизации используется следующая конструкция:
В версии 2:
using TID = System.UInt32;
using TIDNum = System.Int32;
using TID32 = System.UInt32;

// В версии 3:
using TID = System.UInt64;
using TIDNum = System.Int64;
using TID32 = System.UInt32;
Получение значений атрибута:
long longVal = obj.GetLongInteger("ключ атрибута");
int intVal = obj.GetInteger("ключ атрибута");
TIDNum idVal = obj.GetValue<TIDNum>("ключ атрибута");
TIDNum? idValOrNull = obj.GetValue<TIDNum?>("ключ атрибута");
idVal = obj["ключ атрибута"].GetValueOfType<TIDNum>();
idVal = obj.GetAttribute("ключ атрибута").Value.GetValue<TIDNum>();
