Проверка применимости события к указанному объекту (IsApplicable)
Обработчик вызывается в клиентском коде при показе пользователю списка возможных событий по объекту, на которые он может подписаться. Этот обработчик позволяет скрыть события, не применимые к данному конкретному объекту.
bool IsApplicable( TObject thisObject )
// TObject заменяется на конкретный тип объекта:
// InfoObject, DataContainer, User, Task, 
Обработчик возвращает true, если событие применимо к указанному объекту и пользователь может на него подписаться.

Значок
Иконка UI команды (а так же объектного события, так как событие это подтип UI команды).
Иконка подлежит модификации и переопределению при наследовании. Для переопределения  следует снять наследование "Иконка".
Скриптовой доступ:
UICommand.Icon // Возвращает модифицированную или унаследованную иконку, устанавливает собственную иконку.
UICommand.IconNonModified // Возвращает собственную иконку.
UICommand.DisplayIcon // То же, что Icon.
У команды может быть не установлена собственная иконка, вместо неё используется унаследованная. По умолчанию UICommand.Icon и UICommand.DisplayIcon возвращает null. В этом случае используется иконка по умолчанию уровня БИС.
Иконка UI команды может формироваться динамически в обработчике UpdateState, который вызывается всякий раз, когда системе требуется проверить текущее состояние команды и её доступность для выполнения. В следующем примере UI команда действует как переключатель режима перемещения, устанавливая текст кнопки и иконку в соответствии с текущим значением вспомогательного атрибута:
/// <summary>
/// Обновление состояния элементов интерфейса в соответствие с текущим состоянием объекта
/// </summary>
/// <param name="obj">Выделенный объект,к которому потенциально может быть применена команда</param>
/// <param name="cmdUI">Объект для управления контролом вызова команды</param>
public override void UpdateState( InfoObject obj, ICmdUI cmdUI )
{
    var moveWithChildren = obj.GetValue<Boolean>("MoveWithChildren");
    // Устанавливаем ключ изображения в системном ImageList
    cmdUI.ImageKey = Service.UI.ImageListManager.GetCustomIconImageKey(
         Service.GetIcon(moveWithChildren ? "MoveWithChildren" : "MoveWithoutChildren"));
    cmdUI.Text = moveWithChildren ? "Перемещать с детьми" : "Перемещать без детей";
    cmdUI.Enabled = true;
}

/// <summary>
/// Выполнение команды над указанным объектом
/// </summary>
/// <param name="obj">Объект, к которому следует применить команду</param>
public override void Invoke( InfoObject obj )
{
    obj["MoveWithChildren"] = !obj.GetBoolean("MoveWithChildren");
}

Назначение
Подтип команды (или события объекта), определяющий конкретную разновидность объекта и сигнатуры его обработчиков кастомизации. Имеются три варианта UI команды, отличающиеся способом применения и сигнатурами обработчиков кастомизации:
Команда для одиночного объекта;
Команда для нескольких объектов;
Команда для атрибута объекта.
Дополнительно указываются: ключ атрибута, к которому прицеплена команда, и тип данных атрибута.
Кроме того, UI команды специального подтипа UICommandBase.KindEnum.ObjectEvent определяют события объекта, доступные пользователю для подписки.
Скриптовой доступ:
UICommandBase.KindEnum UICommand.Kind // Возвращает модифицированное значение, устанавливает собственное.
UICommand.KindNonModified // Возвращает собственное значение. 

enum UICommandBase.KindEnum: byte
{
   Undefined = 0,
   /// <summary>
   /// Команда для одиночного объекта
   /// </summary>
   SingleObjectCommand,
   /// <summary>
   /// Команда для нескольких выделенных объектов
   /// </summary>
   MultipleObjectCommand,
   /// <summary>
   /// Команда для атрибута объекта
   /// </summary>
   AttributeCommand,
   /// <summary>
   /// Событие объекта
   /// </summary>
   ObjectEvent,
}
В модификаторе или наследнике не переопределяется. Всегда используется унаследованное значение, если есть предшественник.

Пример простого объектного события для отладки
Пример обработчиков объектного события, которое считается произошедшим при любом изменении объектов. Обработчик CheckState запоминает операцию, которая выполнена с объектом (создание, изменение, удаление) и имя объекта. По Invoke создаётся нагрузка с этими сведениями и информации о том, подписка на какой объект привела к срабатыванию события.
public override bool CheckState( InfoObject subscribedObject, AttributableObject modifiedObject, AttributableObject originalObject,
                                 UserSubscription[] subscriptions, EventNotificationInfo accumulationCache )
{
  foreach( var subscription in subscriptions )
  {
    // Явно проверяем что пользователь установил подписку и на "дочерние"
    // Если нет, то нас интересуют только изменения с тем объектом, на который пользователь подписался
    if( !subscription.IsRecursiveOnChildren && subscribedObject != modifiedObject )
        continue;

    // Запомним, какая операция выполнена с объектом, и его название
    var info = accumulationCache.Get( subscription );
    info.ObjectList.Add( modifiedObject.Operation.GetEnumDescription() + ": " + modifiedObject.ToString() );
  }
  return true;
}

public override void Invoke( EventNotificationInfo accumulationCache )
{
  foreach( var u in accumulationCache.BySubscription )
  {
    var subscription = u.Key;
    var info = u.Value;

    // Если подписанный пользователь, это пустая группа, то ничего слать не будем
    if( subscription.TargetUser.AllChildUsers.IsEmpty() )
      continue;
    // Формируем уведомление пользователю
    var w = new WorkItem( @"WorkLoads\Test\Notification", subscription.TargetUser );
    w[ "Subject" ] = "Уведомление от " + ( subscription.Target != null ? subscription.Target.SafeToString() : subscription.TargetId.ToString() );
    w[ "Text" ] = info.ObjectList.SafeToStringCSL().Replace(", ", "\r\n");

    // Отправляем от имени системы
    w.IsBySystem = true;
    w.Send();
  }
}

Пример реализации объектного события (модуль планирования)
Для примера рассмотрим уведомление о появлении или изменении задачи модуля планирования. Ниже приведены фрагменты возможного скрипта кастомизации объектного события, определённого на контейнере, в котором хранятся задачи модуля планирования.
Обработчик, определяющий доступность события для конкретного пользователя
В данном случае он тривиальный. Просто сообщает, что событие доступно. В несколько более сложном случае обработчик мог бы учитывать, например, статус жизненного цикла проекта. В случае его завершения, например, события об изменении содержимого уже не актуальны. Кроме того, этот код мог бы проверить права доступа и предоставить возможность подписки на событие лишь некоторым сотрудникам.
/// <summary>
/// Возвращает true, если подписка на это событие применима к указанному объекту.
/// Вызывается в клиентском коде при показе пользователю списка возможных событий по объекту.
/// </summary>
/// <param name="thisObject">Объект, на события с которым подписались пользователи</param>
/// <returns>true если событие применимо к объекту</returns>
public override bool IsApplicable( DataContainer thisObject )
{
    return true;
}
Обработчик, определяющий факт возникновения события
В данном случае нас интересуют собственные изменения в задачах модуля планирования, но не интересуют изменения в их иерархии. Поэтому изменения в некоторых атрибутах код не воспринимает как состоявшееся событие.
/// <summary>
/// Проверка нового состояния объекта относительно старого для определения факта возникновения данного события.
/// Вызывается в коде серверного сохранения после вызова OnBeforeCommit.
/// Задача метода сложить в <paramref name="accumulationCache"/> сведения для последующей отправки для
/// каждого подписчика.
/// </summary>
/// <param name="subscribedObject">Объект, с подписками на события. Изменённый или один из его родительских.</param>
/// <param name="modifiedObject">Измененный объект (либо <paramref name="subscribedObject"/>, либо один из его дочерних)</param>
/// <param name="originalObject">Исходный объект, как был <paramref name="modifiedObject"/> до внесения изменений</param>
/// <param name="subscriptions">Подписки, по которым следует разослать событие</param>
/// <param name="accumulationCache">Объект для накопления сведений о произошедшем событии, чтобы в последующем 
/// обработчик <see cref="IAttributableObjectEvent.Invoke"/> мог отправить уведомление о событии с одним или несколькими объектами</param>
/// <returns>true если событие произошло и следует вызвать обработчик <see cref="IAttributableObjectEvent.Invoke"/></returns>
public override bool CheckState( InfoObject subscribedObject, 
    AttributableObject modifiedObject, AttributableObject originalObject,
    UserSubscription[] subscriptions, EventNotificationInfo accumulationCache )
{
  // Проверяем, случилось ли событие
  var happened = false;
  if( modifiedObject is InfoObject && modifiedObject.Template.NameKey == "TaskOfProject" )
  {
    // Если изменилось больше одного атрибута, событие состоялось
    var changed = modifiedObject.GetChangedAttributes();
    if( changed.Length > 1 )
       happened = true;
    else
    {
      // Если единственный измененный, это не атрибуты входимости,
      // то событие состоялось
      var attr = changed.FirstOrDefault();
      if( attr != null && attr.NameKey != "SubTaskList" && attr.NameKey != "ParentList" )
        happened = true;
    }
  }

  // Если событие состоялось, для каждого подписчика добавляем сведения об объекте в кэш,
  // чтобы в дальнейшем использовать их для при отправке уведомления. Одного на несколько изменений.
  if( happened )
  {   
    foreach( var subscription in subscriptions )
    {
      var info = accumulationCache.Get( subscription );
      info.ObjectList.Add( modifiedObject );
    }
    return true;
  }
  return false;
}
Рассылка уведомлений пользователям
Если событие состоялось, уведомим об этом подписавшихся пользователей. Для этого для каждого, кроме выполнившего сохранение пользователя, создадим соответствующее почтовое сообщение. Если событие случилось для нескольких объектов сразу, то делаем одно общее уведомление на все объекты для каждого подписчика.

/// <summary>
/// Рассылка накопленных уведомлений о событиях.
/// Вызывается серверным кодом после завершения операции сохранения и вызова триггеров OnAfterCommit.
/// Может вызываться как в той же блокировке, что и операция сохранения, так и в отложенном режиме.
/// </summary>
/// <param name="accumulationCache">Объект с накопленными сведениями о произошедших событиях с объектами, 
/// о которых должна быть произведена рассылка уведомлений</param>
public override void Invoke( EventNotificationInfo accumulationCache )
{
  try
  {
    // Пользователь, выполняющий операцию сохранения. Ему уведомления слать не будем,
    // даже если он подписан
    var user = Service.GetCurrentUser();
    // Для каждого адресата имеющихся подписок создадим сообщение
    foreach( var u in accumulationCache.BySubscription )
    {
      var subscription = u.Key;
      var info = u.Value;
      // Пропустим текущего пользователя
      if ( user == subscription.TargetUser )
        continue;
      // Создаем сообщение пользователю
      var w = new WorkItem( @"WorkLoads\BASIC\Message\SimpleMessageHTML", subscription.TargetUser );

      // Сформируем его заголовок
      w["Subject"] = "Уведомление от " + ( subscription.Target != null ? subscription.Target.SafeToString() : subscription.TargetId.ToString() );
      // Присоединим измененные объекты к сообщению
      w.GetAttribute("Attachments").LinkedInfoObjects = info.ObjectList.OfType<InfoObject>();
      // Уведомлению поставим признак отправки от имени системы
      w.IsBySystem = true;
      // Ставим статус отправки, чтобы все порождённые нагрузки сохранились в одной операции
      w.StatusOperation = WorkItemBase.StatusEnum.Sent;
      // Либо можно было бы отправлять нагрузки по одной, если много подписок не ожидается
      // w.Send();
    }
  }
  catch ( Exception ex)
  {
    // Все возможные исключения перекроем, но сообщим о них в серверном репорте.
    // Если исключения не перекрыть, их увидит пользователь, выполнявший операцию сохранения, а ему
    // скорее всего, не требуется знать, что кому-то не удалось отправить уведомление об изменении.
    // При том, что его действие по сохранению объекта успешно выполнено.
    Service.ReportException(ex);
  }
}

Счётчик
Счётчик это объект для программной генерации очередного уникального числа для использования в каких-либо прикладных идентификаторах. Например, для автогенерации кодов запускаемых Workflow процессов или чего-либо подобного.
Скриптовой класс: AutoIncrementedCounter.
Каждый запрос очередного значения фиксируется в базе и повторно однажды выданный номер не выдаётся. Предназначены они для автонумерования каких-либо объектов. Обычная схема использования счётчиков - это получение объекта по ключу и запрос следующего значения:
var counter = Service.GetAutoIncrementedCounter( @"ключ" );
return counter.GetNextValue(null);
Если у счетчика включена опция "Откатывать изменения счетчика внутри транзакции вместе с транзакцией", то в тех случаях, когда запросы к счетчику происходят внутри серверной обработки операции сохранения, изменения счетчика фиксируются только после фиксации транзакции. Такой вариант использования помогает избежать пропусков в последовательности номеров, если очередная операция сохранения не удалась. Однако такая схема работает только в случае серверного применения счетчика при условии что этот счётчик не был запрошен параллельной обработкой других клиентских запросов, помимо операции сохранения. Запрос следующего значения с клиентской стороны или со стороны серверного скрипта вне рамок операции сохранения сразу же фиксирует в базе выданный номер.
Если у счётчика установлен Интервал обнуления, то в соответствии с настройкой счётчик сбрасывает в 0 текущее значение.
Можно программно переустанавливать значение счётчика:
AutoIncrementedCounterBase.ResetValue( string selectorKey, int newValue )
Виртуальные счётчики
Каждый объект счётчик может выдавать произвольное количество именованных числовых последовательностей (виртуальный счетчик). Виртуальный счетчик определяется строковым ключом, для каждого из которых формируется своя последовательность номеров. Скриптовой доступ к получению очередного значения виртуального счетчика:
var nextValue = counter.GetNextValue( selectorKey );
Для каждого разного ключа selectorKey будет заведен отдельный подчиненный экземпляр счетчика, работающий независимо от своих собратьев.
Внутренняя реализация и устройство
Начиная с версии 2.6.2.460-180420 сохранение значений в базу вынесено в отдельный поток и работает в асинхронном режиме параллельно с другими операциями. Логика выдачи очередного значения и многопоточная синхронизация этих операций реализована в коде сервера. СУБД используется лишь для хранения последних выданных значений. Для большей скорости работы и избегания самоблокировок через базу, реализован оптимистичный вариант обновления значений счётчиков в базе. То есть в момент выдачи очередного значения происходит добавление счётчика в очередь на обновление базы (кроме откатного счётчика внутри серверной обработки операции сохранения, они добавляются в очередь сразу после фиксации транзакции сохранения). Далее отдельный поток в асинхронном режиме сохраняет изменения счётчиков из этой очереди в базе.
Такой режим позволяет безопасно (от самоблокировок через базу) выдавать очередные значения счётчиков параллельно с основной операцией сохранения. Однако, в случае аварийного разрыва соединения с базой или прерывания работы сервера непосредственно после фиксации операции сохранения, но до сохранением изменённых счётчиков, теоретически возможно, что изменения счётчиков не попадут в базу, тогда как выданные значения уже использованы в сохранённых объектах. В дальнейшем, после перезапуска сервера, в таком случае счётчик может выдать очередное значение повторно. Вероятность такого сценария, впрочем, достаточно мала. 
Пример использования
Каждый экземпляр WorkFlow процесса получает свой код, который формируется на основе значения счетчика. Делается это в коде хранимого вычисляемого атрибута:
/// <summary>
/// Подготовка вычисленного атрибута. Возвращает true если значение успешно вычислено
/// </summary>
public override bool Calculate( Task obj, EntityAttribute attr )
{
    // Если хранимое значение уже есть, то его и используем.
    // Для страховки от непреднамеренного перевычисления однажды сформированного кода процесса
    var persisted = attr.PersistedValue;
    if(persisted != null && !persisted.GetValue<String>().IsEmpty() )
    {
        attr.SetValue( persisted.Value );
        return true;
    }

    // Получаем счетчик для формирования номеров процессов
    var counter = Service.GetAutoIncrementedCounter("WFProcessCode");
    if (counter == null)
        return false;
    // Из прототипа процесса достаем строку формата кода процесса
    var format = obj.GetValue<String>("CodeFormat");
    if (format.IsEmpty())
        return false;
    // Из прототипа процесса достаем ключ виртуального счетчика,
    // так чтобы разные шаблоны процессов могли бы использовать нужную последовательность
    // номеров
    var selector = obj.GetAttribute("CounterSelector");
    // Формируем собственно код экземпляра процесса,
    // путём запроса следующего значения виртуального счетчика
    string code;
    if (selector.IsEmpty)
        code = String.Format(format, counter.GetNextValue(null));
    else
        code = String.Format(format, counter.GetNextValue(selector.Value.GetValue<string>()));
    attr.Value.Value = code;
    return true;
}
