Идентификатор (ID)
Идентификатор элемента рабочего стола (аналогичное поле есть и у других скриптовых объектов) это числовой идентификатор по базе соответствующей строки в таблице UserItems.
Скриптовой доступ:
UserItem.Id
UserItem.Id32
UserItem.ObjectIdentifier // Пара тип сущности и числовой идентификатор
Числовой идентификатор объекта используется внутренней инфраструктурой БИС для жёсткого связывания объектов друг с другом в рамках одной СУБД. Числовое значение порождается средствами СУБД через поле автосчётчика.
По числовому идентификатору можно получить объект:
var userItem = Service.GetUserItem( 123 );
Корневые системные элементы можно получить через:
UserItem Service.GetUserItem( SystemItemEnum systemItem );
enum SystemItemEnum: TID
{
  Undefined = 0,
  // Папка для складывания всего, что понравилось
  Favorites = UInt64.MaxValue - 1,
  // Папка для входящей простой почты
  MailInbox = UInt64.MaxValue - 2,
  // Папка для автоматических оповещений
  NotificationsFolder = UInt64.MaxValue - 3,
  // Папка для WF задач к исполнению
  TasksFolder = UInt64.MaxValue - 4,
  // Папка для хранения отправленных почтовых сообщений
  SentFolder = UInt64.MaxValue - 5,
  // Папка для хранения черновиков (еще не отправленных почтовых сообщений)
  DraftsFolder = UInt64.MaxValue - 6,
  // Папка для завершенных WF задач
  ClosedTasksFolder = UInt64.MaxValue - 7,
  // Папка для WF задач к исполнению
  ProcessNotificationsFolder = UInt64.MaxValue - 8,
  // Папка для приостановленных WF задач
  PausedTasksFolder = UInt64.MaxValue - 9,
  // Папка для уведомлений по пользовательским подпискам
  SubscribedEventsFolder = UInt64.MaxValue - 10,
  // Папка для хранения удаленных почтовых сообщений
  DeletedMailFolder = UInt64.MaxValue - 11,

  LastSystemFolder = DeletedMailFolder - 1,
}
Числовое значение SystemItemEnum приведённое к TID также можно использовать в вызовах Service.GetUserItem( TID id ).
Если для созданных элементов программно задан строковый ключ, то добраться до нужного элемента пользователя можно и по пути из ключей, при этом начинается путь со строкового представления одного из элементов SystemItemEnum:
var userItem = Service.GetUserItem( @"MailInbox\ключ-папки" );

Пример автоматического размещения входящих писем по подпапкам
Обработчик ManageMailShortcuts может по собственной логике размещать ссылки на входящие почтовые сообщения в папках рабочего стола пользователя. Например, следующий код, проверяет, есть ли у пользователя дочерняя папка с ключом, совпадающим с ключом шаблона сообщения. Если есть, то входящее сообщение размещается в ней. Если нет, остаётся в основной целевой папке для сообщений или уведомлений:
public override void ManageMailShortcuts( WorkItem obj, UserItemLink creatorLink, UserItemLink[] recipientLinks )
{
    var t = obj.Template;
    if( t != null )
    {
        var tnk = t.NameKey;
        if( tnk.IsEmpty() )
            return;

         switch( t.WorkItemSubKind )
         {
             case WorkItemKind.Notification:
             {
                foreach( var rl in recipientLinks )
                {
                    var u = rl.User;
                    var path = string.Format( "NotificationsFolder\\{0}", t.NameKey );
                    var folder = Service.GetUserItem( u, path );
                    if( folder != null )
                        rl.Parent = folder;
                }
                break;
            }
            case WorkItemKind.Mail:
             {
                foreach( var rl in recipientLinks )
                {
                    var u = rl.User;
                    var path = string.Format( "MailInbox\\{0}", t.NameKey );
                    var folder = Service.GetUserItem( u, path );
                    if( folder != null )
                        rl.Parent = folder;
                }
                break;
            }
        }            
    }
}
При этом, чтобы появились папки для таких сообщений, для пользователя должны быть предоставлены соответствующие механизмы, так как в штатных средствах пользовательского интерфейса дополнительные поля для отображения ключа папки - скрыты. В данном случае пользователь создаёт такие подпапки UI командой на входящей нагрузке, которая создаёт пользователю подпапку для входящих нагрузок своего шаблона. То есть пользователь выбирает нагрузки нужного шаблона и для них создаёт отдельную папку. Код такой команды может выглядеть так:
public override void UpdateState( IEnumerable<WorkItem> objects, ICmdUI cmdUI )
{
  // Команда доступна только для почтовых сообщений и уведомлений
  cmdUI.Enabled = !objects.All( o => o.Template != null && ( o.Template.WorkItemSubKind != WorkItemKind.Notification && o.Template.WorkItemSubKind != WorkItemKind.Mail ) );
}

public override void Invoke( IEnumerable<WorkItem> objects )
{
 var u = Service.GetCurrentUser();
 var rootNotifications = Service.GetUserItem( u, "NotificationsFolder" );
 var rootMailInbox = Service.GetUserItem( u, "MailInbox" );

 var fcount = 0;
 var ftotal = 0;
 foreach( var t in objects.Select( o => o.Template ).Where( t => t.WorkItemSubKind == WorkItemKind.Notification ).SkipNull().Distinct() )
 {
   // Ищем и при необходимости создаём папку для уведомлений с ключом названием и иконкой как у шаблона сообщения
   var f = rootNotifications.AllChildren.FirstOrDefault( c => c.NameKey == t.NameKey );
   if( f == null )
   {
     f = new UserItem( UserItemBase.KindEnum.Folder, u, rootNotifications, t.NameKey );
     f.NameUI = t.NameUI;
     f.Icon = t.DisplayIcon;
     f.Save();
     fcount++;
    }
    ftotal++;
 }

 foreach( var t in objects.Select( o => o.Template ).Where( t => t.WorkItemSubKind == WorkItemKind.Mail ).SkipNull().Distinct() )
 {
   // Ищем и при необходимости создаём папку для уведомлений с ключом названием и иконкой как у шаблона сообщения
   var f = rootMailInbox.AllChildren.FirstOrDefault( c => c.NameKey == t.NameKey );
   if( f == null )
   {
     f = new UserItem( UserItemBase.KindEnum.Folder, u, rootMailInbox, t.NameKey );
     f.NameUI = t.NameUI;
     f.Icon = t.DisplayIcon;
     f.Save();
     fcount++;
   }
   ftotal++;
 }

 // Сообщаем пользователю, что получилось и спрашиваем, надо ли перенести выбранные сообщения в соответствующие папки
 var mess = string.Format( "Создано (существует) {0}({1}) папок.\r\nПереместить выбранные Сообщения в соответствующие папки?", fcount, ftotal-fcount );
 if( Service.UI.ShowMessage( mess, MessageBoxButtons.YesNo ) == DialogResult.Yes )
 {
  foreach( var obj in objects.Where( o => o.Template != null && o.Template.WorkItemSubKind == WorkItemKind.Notification ) )
  {
   // Находим соответствующую ссылку на очередную нагрузку, ищем для неё папку и переносим ссылку на нагрузку в эту папку
   var link = Service.GetUserItemLinks( u, rootNotifications, obj, true ).FirstOrDefault();
   if( link != null ) 
   {
    var wt = obj.Template;
    if( wt != null )
    {
     var folder = rootNotifications.Children.FirstOrDefault( ui => ui.NameKey == wt.NameKey );
     if( folder != null )
     {
      link.Parent = folder;
      link.Save();
     }
    }
   }
  }

  foreach( var obj in objects.Where( o => o.Template != null && o.Template.WorkItemSubKind == WorkItemKind.Mail ) )
  {
   // Находим соответствующую ссылку на очередную нагрузку, ищем для неё папку и переносим ссылку на нагрузку в эту папку
   var link = Service.GetUserItemLinks( u, rootMailInbox, obj, true ).FirstOrDefault();
   if( link != null ) 
   {
    var wt = obj.Template;
    if( wt != null )
    {
     var folder = rootMailInbox.Children.FirstOrDefault( ui => ui.NameKey == wt.NameKey );
     if( folder != null )
     {
      link.Parent = folder;
      link.Save();
     }
    }
   }
  }
 }
}
Примечание: Если число возможно выбранных пользователем сообщений может оказаться заметным, то следовало бы использовать групповое сохранение вместо множества одиночных, поместив вторую часть кода, который переносит ссылки на сообщения по подпапкам в групповой контекст с общим сохранением:
using( Service.EnterNewGroupOperation())
{
  ...
  Service.SaveChanges();
}

Содержимое папок пользовательского рабочего стола (UserItemLink)
Ссылка на объект (UserItemLink) в папке пользовательского рабочего стола (UserItem) - это пара объектов, при помощи которых формируется рабочая среда пользователя при работе в информационной системе.
Скриптовой класс: UserItemLink.
Таблица в базе: UserItemLinks.
Элементы пользовательского стола - это папки для ссылок (UserItemLinks) на другие прикладные объекты информационной системы. До содержимого конкретного элемента (список ссылок на реальные объекты) можно добраться через:
// Возвращает массив ссылок на объекты, хранящихся в этом элементе.
UserItemLink[] UserItem.Shortcuts

// Возвращает массив ссылок на объекты, хранящихся в этом элементе, 
// относящиеся к указанному пользователю (на клиенте игнорируется).
UserItemLink[] UserItem.GetShortcuts( User user )

// Возвращает массив ссылок на указанный объект, хранящихся в этом элементе, 
// относящиеся к указанному пользователю (на клиенте игнорируется).
UserItemLink[] UserItem.GetShortcuts( User user, AttributableObject target )
Класс UserItemLink содержит три основных свойства, которые можно программно установить и сохранить в базу обычным для скриптовых объектов способом:
class UserItemLink
{
  // Доступ к родительскому объекту
  UserItem Parent;

  // Доступ к пользователю-владельцу этого объекта
  User User;

  // Целевой объект данной ссылки
  AttributableObject Target;
}
А так же соответствующие конструкторы для создания ссылок по целевому объекту с привязкой к элементу рабочего стола и пользователю.
В классе Service есть прямой метод для запроса ссылок по пути к элементу рабочего стола:
// Доступ к шорткатам по идентификатору элемента ПРС и целевому объекту
// user - Пользователь, чьи ссылки интересуют
// item - Элемент рабочего стола
// target - Целевой объект, ссылки на который интересуют. Если null, то возвращаются все
// preload - Если true, то на клиенте происходит предварительная загрузка целевых объектов ссылок
UserItemLink[] Service.GetUserItemLinks( User user, UserItem item, AttributableObject target, bool preload )
По команде "Добавить в избранное" в пользовательском интерфейсе клиента пользователю предлагается выбрать папку дочернюю к системному элементу SystemItemEnum.Favorites, после чего в ней создаётся:
var item = new UserItemLink( userItem, targetObject );
item.Save();
Когда пользователю приходит почтовое сообщение или уведомление, то серверный код создаёт ссылку в рабочем столе отправителя и в рабочем столе получателя. Тем самым один и тот же объект сообщения появляется и отправителя в папке Отправленные (SentFolder) и у получателя в папке Входящие (MailInbox). См. Управление распределением по папкам входящей почты (ManageMailShortcuts). При удалении ссылки на почтовое сообщение происходит фоновая проверка, была ли эта ссылка последней и если да, то почтовое сообщение физически удаляется из базы.

Элемент реестра
Элемент реестра это объекты, выстроенные в дерево, для хранения системных и прикладных настроек чего-либо. По своей природе и назначению, реестр в БИС очень похож на Реестр ОС Windows.
Скриптовой класс: RegistryItem.
Дерево элементов реестра обычно устроено так, что узловые элементы играют роль папок (значение этих элементов не установлено), а конечным элементам-листьям (чаще всего с ключом Value) устанавливается какое-либо значение. Чтение значения обычно происходит по пути из ключей:
String host = Service.GetCommonRegistryValue( @"Server\ServerAddressPort\Address\Value", "" );
Типом значения элемента реестра могут быть:
текст (String);
набор строк (String[]);
вещественное число (double);
целое число (int, long в BISv3);
ссылка на объект (ScriptingObject, DataObjectIdentifier);
цвет (Color);
бинарные данные (byte[]).
Элемент реестра может быть клиентским или серверным. Серверные ветви реестра не загружаются в клиентское приложения (кроме конфигураторов), они доступны только на стороне сервера.
Наименование, и заметки элемента реестра могут содержать понятное название настройки и пояснения о возможных значениях.
Элементы реестра могут быть общими или привязанными к пользователю - пользовательскими. Пользовательские элементы не экспортируются вместе с конфигурацией. Пользовательские ветви реестра загружаются только в клиентские приложения своего владельца. (Владельцем элемента реестра может быть группа пользователей).
Скриптовой доступ к элементам реестра
Для работы именно с элементами реестра, как с объектами есть метод:
Доступ к значениям элементов реестра осуществляется по ключу или, точнее, по путям из ключей при помощи методов статического класса Service.
// Возвращает элемент реестра указанного типа по заданному пути для заданного пользователя
// registryItem - Элемент, с которого начинаем поиск
// path - Путь к элементу от корня по ключам
// user - Пользователь, для которого ищем настройку; null означает поиск глобальной настройки
// eType - Тип значения требуемого элемента реестра
// clientSide - true если интересует клиентская настройка
// createIfMissing - true, если требуется создать элемент при его отсутствии (элемент будет в несохраненном состоянии)
// Возвращает найденный или вновь созданный элемент реестра
RegistryItem Service.GetRegistryItem( 
   RegistryItem registryItem, 
   String path, 
   User user, 
   RegistryItemBase.DataTypeEnum eType,
   bool clientSide,
   bool createIfMissing )
С его помощью можно запросить нужного типа элемент (общий или пользовательский) по указанному пути клиентский или серверный с возможностью автоматического создания, если нет существующего (в этом случае метод вернёт несохранённый объект RegistryItem, который вызывающий код может инициализировать и сохранить).
Имеется так же и ряд методов для чтения значений элементов реестра по пути:
T Service.GetRegistryValue<T>( String path, User user, T defaultValue )
T Service.GetCommonRegistryValue<T>( String path )
T Service.GetUserRegistryValue<T>( String path ) // Возвращает значение для текущего пользователя
Эти методы ищут элемент по пути выбирая ближайшие пользовательские ветки, если есть выбор.
Для установки значений реестра имеются методы:
RegistryItem Service.SetRegistryValue<T>( RegistryItem registryItem, String path, User user, T value, bool saveImmediately )
RegistryItem Service.SetCommonRegistryValue<T>( String path, T value )
void Service.SetCommonRegistryValueAsync<T>( String path, T value ) // асинхронная версия без ожидания подтверждения от сервера
RegistryItem Service.SetUserRegistryValue<T>( String path, T value )

Ключ элемента реестра
Ключ элемента реестра (аналогичное поле есть и у других скриптовых объектов) используется как строковый идентификатор для программного доступа к элементу.
Скриптовой доступ:
RegistryItem.NameKey
Доступ к значениям элементов реестра осуществляется по ключу или, точнее, по путям из ключей при помощи методов статического класса Service.
// Возвращает элемент реестра указанного типа по заданному пути для заданного пользователя
// registryItem - Элемент, с которого начинаем поиск
// path - Путь к элементу от корня по ключам
// user - Пользователь, для которого ищем настройку; null означает поиск глобальной настройки
// eType - Тип значения требуемого элемента реестра
// clientSide - true если интересует клиентская настройка
// createIfMissing - true, если требуется создать элемент при его отсутствии (элемент будет в несохраненном состоянии)
// Возвращает найденный или вновь созданный элемент реестра
RegistryItem Service.GetRegistryItem( 
   RegistryItem registryItem, 
   String path, 
   User user, 
   RegistryItemBase.DataTypeEnum eType,
   bool clientSide,
   bool createIfMissing )
Примечание: в ключах не допускается использование символов: .,;\&*/.

Настройка конечной системы (не изменяется при импорте/обновлении конфигурации)
Если установлено, то элемент реестра считается относящимся к целевой системе и не перезаписывается при импорте пакетов конфигурации (если при импорте явно не указано перезаписывать локальные свойства).
Примечание: пользовательские элементы реестра (то есть те, у которых установлен владелец) считаются локальными в любом случае и не относятся к объектам конфигурации.
Скриптовой доступ:
// Фактическое свойство инвертированное
bool isLocal =  !RegistryItem.IsConfigurationObject;

Тип данных
Тип данных для элемента реестра.
Скриптовой доступ:
RegistryItemBase.DataTypeEnum RegistryItem.DataType

public enum DataTypeEnum
{
  Undefined = 0,

  // Простой текстовый атрибут
  Text,

  // Вещественное число
  Number,

  // Целое число
  IntegerNumber,

  // Ссылка на объект
  LinkToObject,

  // Бинарные данные byte[]
  BinaryData,

  // Массив строк String[]
  ArrayOfStrings,

  // Цвет System.Drawing.Color
  Color,
}

