Пример использования реестра при отправке PUSH сообщения
В следующем фрагменте происходит чтение ключа приложения Google для отправки PUSH сообщения на мобильный телефон. Этот ключ используется для формирования HTTPs запроса:
public static FCMResponse SendFCMNotification( PushMessage message )
{
    var serverKey = Service.GetCommonRegistryValue<String>(@"Server\PushMessages\FCM\WebMobile\ServerAuthorizationKey\Value");
      if( serverKey.IsEmpty() )
          return null;

    var webAddr = "https://fcm.googleapis.com/fcm/send";
    var httpWebRequest = (HttpWebRequest)WebRequest.Create(webAddr);
    httpWebRequest.ContentType = "application/json";
    httpWebRequest.Headers.Add(HttpRequestHeader.Authorization,"key=" + serverKey);
    httpWebRequest.Method = "POST";
    using (var streamWriter = new StreamWriter(httpWebRequest.GetRequestStream()))
    {
        streamWriter.Write(message.ToJson());
        streamWriter.Flush();
    }

    String result;
    var httpResponse = (HttpWebResponse)httpWebRequest.GetResponse();
    using (var streamReader = new StreamReader(httpResponse.GetResponseStream()))
    {
        result = streamReader.ReadToEnd();
    }
    var res = Newtonsoft.Json.JsonConvert.DeserializeObject<FCMResponse>( result );
    return res;
}
